using SpecOp = Configuration::SpecialOperatingActivity;

static QRegularExpression const kDecodeLineTimestampPattern {R"(^(\d{6})\s+)"};

static bool has_decode_line_timestamp (QString const& text)
{
  return kDecodeLineTimestampPattern.match (text).hasMatch ();
}

static QStringList split_packed_decode_rows (QString rawLine)
{
  rawLine.replace ('\r', ' ');
  rawLine.replace ('\n', ' ');
  QString normalized = rawLine.trimmed ();
  if (normalized.isEmpty () || normalized == "0") {
    return {};
  }

  QString tsPrefix;
  auto const tsMatch = kDecodeLineTimestampPattern.match (normalized);
  if (tsMatch.hasMatch ()) {
    tsPrefix = tsMatch.captured (1);
  }

  QStringList rows;
  int start = 0;
  int wsRun = 0;
  bool sawSplit = false;
  auto flushChunk = [&] (int endExclusive) {
    if (endExclusive <= start) {
      return;
    }
    QString chunk = normalized.mid (start, endExclusive - start).trimmed ();
    if (!chunk.isEmpty ()) {
      rows << chunk;
    }
  };

  for (int i = 0; i < normalized.size (); ++i) {
    auto const c = normalized.at (i);
    bool const isWs = (c == QChar (' ') || c == QChar::Nbsp || c == QChar ('\t'));
    if (isWs) {
      ++wsRun;
    } else {
      if (wsRun >= 6) {
        sawSplit = true;
        flushChunk (i - wsRun);
        start = i;
      }
      wsRun = 0;
    }
  }
  flushChunk (normalized.size ());

  if (!sawSplit || rows.size () <= 1) {
    return {normalized};
  }

  for (int i = 1; i < rows.size (); ++i) {
    if (!tsPrefix.isEmpty () && !has_decode_line_timestamp (rows.at (i))) {
      rows[i].prepend (tsPrefix + " ");
    }
  }
  return rows;
}

static int decoded_line_mode_column (QString const& line)
{
  // Decodes with seconds in UTC timestamp (hhmmss) are shifted by +2 columns.
  return line.indexOf (' ') > 4 ? 21 : 19;
}

static bool is_decode_mode_marker (QChar c)
{
  switch (c.unicode ()) {
    case '~':
    case '+':
    case '@':
    case '#':
    case ':':
    case '&':
    case '^':
      return true;
    default:
      return false;
  }
}

static QString udp_decode_message_text (QString const& decodeLine)
{
  // Robust payload extraction for UDP decode packets.
  // Some FT2 rows arrive with variable spaces after the mode marker;
  // fixed mid(24)/mid(22) can drop the first payload character.
  static QRegularExpression const payloadRegex {
    R"(^\s*\d{4,6}\s+[+\-−]?\d+\s+[+\-−]?\d+(?:\.\d+)?\s+\d+\s*(?:[~+@:#&\^])?\s*(.*)$)"
  };
  auto const payloadMatch = payloadRegex.match (decodeLine);
  if (payloadMatch.hasMatch ()) {
    return payloadMatch.captured (1);
  }

  int const modeColumn = decoded_line_mode_column (decodeLine);
  if (modeColumn >= 0 && decodeLine.size () > modeColumn) {
    int payloadStart = modeColumn;
    if (is_decode_mode_marker (decodeLine.at (modeColumn))) {
      ++payloadStart;
    }
    while (payloadStart < decodeLine.size () && decodeLine.at (payloadStart).isSpace ()) {
      ++payloadStart;
    }
    return decodeLine.mid (payloadStart);
  }

  auto const has_seconds = decodeLine.left (6).trimmed ().size () == 6 && decodeLine.at (4).isDigit ();
  return decodeLine.mid (has_seconds ? 24 : 22);
}

static QString canonical_decode_payload_for_dedupe (QString const& decodeLine, QString const& mode)
{
  QString payload = udp_decode_message_text (decodeLine).remove ("<").remove (">").simplified ().toUpper ();
  if (payload.isEmpty ()) {
    return payload;
  }

  // FT2 async/triggered decoders can append a trailing annotation token
  // ("T", "a2", etc.) to the same payload. Keep it visible in the panes,
  // but ignore it for dedupe/confirmation so the async and sync copies
  // collapse to one logical decode.
  if (mode == "FT2") {
    payload.replace (QRegularExpression {R"((?:\s+\?)?(?:\s+[AQ]\d|\s+[AQ]\*|\s+T)\s*$)"},
                     QString {});
    payload = payload.simplified ();
  }

  return payload;
}

static QString sanitized_ft2_payload_for_filter (QString const& decodeLine)
{
  QString payload = udp_decode_message_text (decodeLine).trimmed ();
  if (payload.isEmpty ()) {
    return payload;
  }

  payload.replace (QRegularExpression {R"((?:\s+\?)?(?:\s+[AQ]\d|\s+[AQ]\*|\s+T)\s*$)"},
                   QString {});
  return payload.simplified ();
}

static void normalize_ft2_mode_marker (QString& line, QString const& currentMode)
{
  if (currentMode != "FT2") {
    return;
  }

  // Decoder output can contain Unicode minus variants (e.g. U+2212).
  // They can render with different glyph widths and visually break column
  // alignment in decode panes; normalize them to ASCII '-'.
  line.replace (QChar {0x2212}, QChar {'-'});
  line.replace (QChar {0x2012}, QChar {'-'});
  line.replace (QChar {0x2013}, QChar {'-'});
  line.replace (QChar {0x2014}, QChar {'-'});

  // Normalize the FT2 decode prefix to fixed-width columns:
  // UTC  dB  DT  Freq  +  Message
  //
  // Some decoder paths can emit variable spacing and/or Unicode minus signs,
  // which shifts the mode marker and breaks visual column alignment.
  static QRegularExpression const ft2PrefixRx {
    R"(^\s*(\d{4,6})\s+([+\-−]?\d+)\s+([+\-−]?\d+(?:\.\d+)?)\s+(\d+)\s+([~+])\s+(.*)$)"
  };
  auto const prefixMatch = ft2PrefixRx.match (line);
  if (prefixMatch.hasMatch ()) {
    QString utc = prefixMatch.captured (1).trimmed ();
    int const utcWidth = utc.size () >= 6 ? 6 : 4;
    utc = utc.rightJustified (utcWidth, QChar {'0'});

    QString snrText = prefixMatch.captured (2);
    snrText.replace (QChar {0x2212}, QChar {'-'});
    bool snrOk = false;
    int const snr = snrText.toInt (&snrOk);

    QString dtText = prefixMatch.captured (3);
    dtText.replace (QChar {0x2212}, QChar {'-'});
    bool dtOk = false;
    double const dt = dtText.toDouble (&dtOk);

    bool freqOk = false;
    int const freq = prefixMatch.captured (4).toInt (&freqOk);

    if (snrOk && dtOk && freqOk) {
      QString const payload = prefixMatch.captured (6).trimmed ();
      // Keep exactly two spaces after the mode marker to preserve
      // DecodedText fixed columns (mode at 19/21, message at 22/24).
      line = QString {"%1 %2 %3 %4 +  %5"}
        .arg (utc, utcWidth, QChar {'0'})
        .arg (snr, 3)
        .arg (dt, 4, 'f', 1)
        .arg (freq, 4)
        .arg (payload);
      return;
    }
  }

  // Fallback for legacy fixed-column decodes.
  int const modeColumn = decoded_line_mode_column (line);
  if (modeColumn >= 0 && line.size () > modeColumn && line.at (modeColumn) == QChar {'~'}) {
    line[modeColumn] = QChar {'+'};
  }
}

static void apply_async_ft2_tdelta (QString& line, qint64 asyncRxStartMs)
{
  if (asyncRxStartMs <= 0 || line.isEmpty ()) {
    return;
  }

  // Rewrite TΔ through structured parsing instead of fixed offsets:
  // fixed-position replacement can merge SNR/DT fields and break FT2 routing.
  static QRegularExpression const ft2PrefixRx {
    R"(^\s*(\d{4,6})\s+([+\-−]?\d+)\s+([+\-−]?\d+(?:\.\d+)?)\s+(\d+)\s+([~+@:#&\^])\s+(.*)$)"
  };
  auto const prefixMatch = ft2PrefixRx.match (line);
  if (!prefixMatch.hasMatch ()) {
    return;
  }

  QString utc = prefixMatch.captured (1).trimmed ();
  int const utcWidth = utc.size () >= 6 ? 6 : 4;
  utc = utc.rightJustified (utcWidth, QChar {'0'});

  QString snrText = prefixMatch.captured (2);
  snrText.replace (QChar {0x2212}, QChar {'-'});
  bool snrOk = false;
  int const snr = snrText.toInt (&snrOk);

  bool freqOk = false;
  int const freq = prefixMatch.captured (4).toInt (&freqOk);

  QString const marker = prefixMatch.captured (5);
  QString const payload = prefixMatch.captured (6).trimmed ();

  if (!snrOk || !freqOk || marker.isEmpty () || payload.isEmpty ()) {
    return;
  }

  double tdelta = (QDateTime::currentMSecsSinceEpoch () - asyncRxStartMs) / 1000.0;
  if (!qIsFinite (tdelta) || tdelta < 0.0) {
    tdelta = 0.0;
  }
  // Keep FT2 DT field width stable (f4.1), otherwise columns drift.
  tdelta = qMin (tdelta, 99.9);

  line = QString {"%1 %2 %3 %4 %5  %6"}
    .arg (utc, utcWidth, QChar {'0'})
    .arg (snr, 3)
    .arg (tdelta, 4, 'f', 1)
    .arg (freq, 4)
    .arg (marker)
    .arg (payload);
}

static QString udp_client_id_from_application_name ()
{
  // Keep WSJT-X compatibility for third-party UDP clients that key off
  // the traditional application identifier instead of just the schema.
  return QStringLiteral ("WSJTX");
}

static QDateTime decode_line_timestamp_for_log (QDateTime fallbackUtc, QString const& message)
{
  if (!fallbackUtc.isValid ()) {
    fallbackUtc = QDateTime::currentDateTimeUtc ();
  }

  int start = 0;
  while (start < message.size () && message.at (start).isSpace ()) {
    ++start;
  }

  int digits = 0;
  while ((start + digits) < message.size ()
         && message.at (start + digits).isDigit ()
         && digits < 6) {
    ++digits;
  }

  if ((digits != 4 && digits != 6)
      || ((start + digits) < message.size () && !message.at (start + digits).isSpace ())) {
    return fallbackUtc;
  }

  auto const token = message.mid (start, digits);
  auto const parsed = QTime::fromString (token, digits == 6 ? "hhmmss" : "hhmm");
  if (!parsed.isValid ()) {
    return fallbackUtc;
  }

  QDateTime candidate {fallbackUtc.date (), parsed, Qt::UTC};
  auto const delta = fallbackUtc.secsTo (candidate);
  if (delta > 12 * 3600) {
    candidate = candidate.addDays (-1);
  } else if (delta < -12 * 3600) {
    candidate = candidate.addDays (1);
  }

  return candidate;
}

void MainWindow::pruneNearDuplicateDecodeCache (qint64 nowMs)
{
  if (m_decodeDedupeLastPruneMs > 0 && (nowMs - m_decodeDedupeLastPruneMs) < 5000) {
    return;
  }
  qint64 const keepMs = qMax (m_decodeDedupeWindowMs * 6, 12000);
  for (auto it = m_decodeDedupeCache.begin (); it != m_decodeDedupeCache.end (); ) {
    if ((nowMs - it.value ().lastSeenMs) > keepMs) {
      it = m_decodeDedupeCache.erase (it);
    } else {
      ++it;
    }
  }
  m_decodeDedupeLastPruneMs = nowMs;
}

bool MainWindow::shouldSuppressNearDuplicateDecode (DecodedText const& decodedtext)
{
  if (!(m_mode == "FT2" || m_mode == "FT4" || m_mode == "FT8")) {
    return false;
  }
  if (decodedtext.isTX ()) {
    return false;
  }

  QString payload = canonical_decode_payload_for_dedupe (decodedtext.string (), m_mode);
  if (payload.isEmpty ()) {
    return false;
  }

  QString deCall;
  QString deGrid;
  decodedtext.deCallAndGrid (deCall, deGrid);
  QString keyCall = deCall.trimmed ().toUpper ();
  if (keyCall.isEmpty ()) {
    keyCall = decodedtext.CQersCall ().trimmed ().toUpper ();
  }
  if (keyCall.isEmpty ()) {
    QString c = decodedtext.call ().trimmed ().toUpper ();
    if (c != "CQ" && c != "QRZ" && c != "DE") {
      keyCall = c;
    }
  }
  if (keyCall.isEmpty ()) {
    keyCall = payload.section (' ', 0, 0).trimmed ();
  }
  if (keyCall.isEmpty ()) {
    return false;
  }

  int const audioFreq = decodedtext.frequencyOffset ();
  QString const freqKey = (m_mode == "FT2")
      ? QStringLiteral ("FT2")
      : QString::number (audioFreq);
  QString const grid4 = deGrid.left (4).toUpper ();
  QString const key = QString {"%1|%2|%3|%4|%5"}
      .arg (m_mode, keyCall, freqKey, grid4, payload);

  qint64 const nowMs = QDateTime::currentMSecsSinceEpoch ();
  pruneNearDuplicateDecodeCache (nowMs);

  int const snr = decodedtext.snr ();
  auto it = m_decodeDedupeCache.find (key);
  if (it == m_decodeDedupeCache.end ()) {
    DecodeDedupeEntry entry;
    entry.lastSeenMs = nowMs;
    entry.bestSnr = snr;
    m_decodeDedupeCache.insert (key, entry);
    return false;
  }

  DecodeDedupeEntry& entry = it.value ();
  if ((nowMs - entry.lastSeenMs) > m_decodeDedupeWindowMs) {
    entry.lastSeenMs = nowMs;
    entry.bestSnr = snr;
    return false;
  }

  entry.lastSeenMs = nowMs;
  if (m_mode == "FT2") {
    if (snr > entry.bestSnr) {
      entry.bestSnr = snr;
    }
    return true;    // FT2 async/sync: suppress same payload even if a later hypothesis is stronger
  }
  if (snr <= entry.bestSnr) {
    return true;    // duplicate not better than best in the active window
  }
  entry.bestSnr = snr;
  return false;     // allow stronger duplicate
}

void MainWindow::updateAsyncL2ControlsVisibility ()
{
  if (!ui) {
    return;
  }

  bool const isFt2 = (m_mode == "FT2");
  bool const asyncEnabled = ui->cbAsyncDecode && ui->cbAsyncDecode->isChecked ();

  if (ui->cbAsyncDecode) {
    if (isFt2) {
      // FT2 rule: Async L2 is mandatory and always ON.
      ui->cbAsyncDecode->setChecked (true);
      m_asyncL2DefaultAppliedForCurrentFt2 = true;
      ui->cbAsyncDecode->setEnabled (false);
    } else {
      ui->cbAsyncDecode->setEnabled (true);
      // Force async L2 OFF when leaving FT2 to avoid hidden active state.
      ui->cbAsyncDecode->setChecked (false);
      m_asyncL2DefaultAppliedForCurrentFt2 = false;
    }
    // Keep only the status badge visible in FT2 (no user toggle).
    ui->cbAsyncDecode->setVisible (false);
  }

  if (ui->labelAsymxBadge) {
    ui->labelAsymxBadge->setVisible (false);
  }

  if (ui->labelAsyncL2Active) {
    ui->labelAsyncL2Active->setText (tr ("Async L2 Mode On"));
    ui->labelAsyncL2Active->setStyleSheet ("QLabel{color:#003300; background-color:#00e676; font-weight:bold; font-size:11px; padding:1px 6px; border-radius:7px;}");
    ui->labelAsyncL2Active->setVisible (isFt2 && asyncEnabled);
  }

  if (m_asyncVis) {
    bool const showVisualizer = isFt2 && asyncEnabled;
    m_asyncVis->setTransmitting (m_transmitting);
    if (showVisualizer) {
      if (!m_asyncVis->isVisible ()) {
        m_asyncVis->setVisible (true);
      }
      if (m_asyncDecodeTimer.isActive ()) {
        m_asyncVis->start ();
      }
    } else {
      m_asyncVis->stop ();
      m_asyncVis->setVisible (false);
    }
  }

  if (ui->cbDualCarrier) {
    if (!isFt2 && ui->cbDualCarrier->isChecked ()) {
      ui->cbDualCarrier->setChecked (false);
    }
    ui->cbDualCarrier->setVisible (isFt2);
  }

  if (ui->labelDualCarrierWarning) {
    bool const dualCarrierEnabled = ui->cbDualCarrier && ui->cbDualCarrier->isChecked ();
    ui->labelDualCarrierWarning->setVisible (isFt2 && dualCarrierEnabled);
  }

  if (ui->cbAutoTogglePeriod) {
    if (isFt2 && ui->cbAutoTogglePeriod->isChecked ()) {
      // Alt 1/2 is meaningful only outside FT2: avoid hidden active state.
      ui->cbAutoTogglePeriod->setChecked (false);
    }
    ui->cbAutoTogglePeriod->setVisible (!isFt2);
  }

  if (ui->cbHoldTxFreq) {
    if (isFt2 && ui->cbHoldTxFreq->isChecked ()) {
      ui->cbHoldTxFreq->setChecked (false);
    }
    ui->cbHoldTxFreq->setVisible (!isFt2);
  }

  if (ui->txFirstCheckBox) {
    if (isFt2 && ui->txFirstCheckBox->isChecked ()) {
      ui->txFirstCheckBox->setChecked (false);
    }
    ui->txFirstCheckBox->setVisible (!isFt2);
  }

  dt_correction_label.setVisible (!isFt2);
}

