  m_rttyModulator.reset(new decodium::rtty::RTTYModulator(48000, 45.45, 2125.0, 2295.0, 2.0, this));
  connect(m_rttyTerminal.data(), &RTTYTerminalWidget::transmitText, this, &MainWindow::transmitRttyText);
