  connect (m_messageClient, &MessageClient::setup_tx, [this] (int newTxMsgIdx, QString const& msg, bool param0, bool param1, QString const& check, quint32 offset) {    //avt 11/16/20
      if (!m_externalCtrl) {
        m_dblClk = false; //avt 1/1/21
        m_checkCmd = "";  //avt 1/1/21
        m_dxCall = "";    //avt 11/12/21
        m_bOffset = false;//avt 11/13/21
        m_txHaltClk = false;  //avt 12/18/21
        m_txEnableClk = false;  //avt 1/28/24
        m_enableButtonNotify = true;  //avt 1/23/24
        showStatusMessage("Controller initiated"); //avt 12/16/21
        debugToFile(QString{});
        debugToFile("setup        Controller initiated");
        m_externalCtrl = true;    //avt 11/19/20 configure for external controller special cases
        initExternalCtrl();       //disable Call 1st and Auto buttons 

        setMyContinent();
        statusUpdate ();
        //QApplication::beep();    //for debug
      }

      if (newTxMsgIdx) {          //perform some QSO state action (mostly)

        if (newTxMsgIdx == 6 || newTxMsgIdx == 4) {   //set up some kind of CQ, set options
          debugToFile("setupCq");   //avt 2/2/24
          //misc setup actions (*affects QSO state*)
          ui->tx1->setEnabled(!param0);   //avt 1/1/21 set/clear skip grid msg
          if (param1 != m_send_RR73) on_txrb4_doubleClicked();   //avt 1/5/24 set/clear use of RR73 msg
          //*now* set QSO state
          if (!msg.isEmpty()) {   //set up directed CQ
            ui->tx6->setText(msg);
          } else {
            genCQMsg();           //set up std CQ
          }
          m_bCallingCQ = true;  //allows tail-enders to be picked up
          m_ntx = 6;
          m_bAutoReply = false;
          m_QSOProgress = CALLING;
          ui->txrb6->setChecked(true);

          if (newTxMsgIdx == 4) {
            m_enableButtonNotify = false; //avt 2/2/24
            process_autoButton(true);
            m_enableButtonNotify = true; //avt 2/2/24
          }
          debugToFile(QString{"setupCq      statusUpdate, m_auto:%1 autoButton m_autoButtonState:%2"}.arg(m_auto).arg(m_autoButtonState));
          statusUpdate();                 //used as confirmation of UDP requests enabled
          return;
        }

        //avt 12/7/23 enable debug logging
        if (newTxMsgIdx == 5) {   
          m_debugLog = true;
          debugToFile(QString{});
          debugToFile("setupCq      Logging enabled");
          return;
        }

        if (newTxMsgIdx == 7) {           //ack req avt 12/16/21
          m_checkCmd = check;             //used as confirmation of cmd
          if (param0) statusUpdate();   //param0 = replyReqd, used as confirmation of UDP requests enabled
          if (param1) {                  //param1 = enableTimeout
            externalCtrlTimer.start(60000);  //(re)start external controller heartbeat detect timer, chgd to 60 sec avt 12/28/23
          } else {
            externalCtrlTimer.stop();     //stop external controller heartbeat detect timer
          }
          return;
        }

        if (newTxMsgIdx == 8) {           //disable Tx
          debugToFile(QString{});
          debugToFile("setupCq      disableTx");
          m_enableButtonNotify = false; //avt 1/23/24
          process_autoButton(false);
          ui->autoButton->setChecked(param0);
          m_autoButtonState = param0;   //avt 10/2/25
          m_enableButtonNotify = true; //avt 1/23/24
          //debugToFile(QString{"             m_auto:%1 autoButton m_autoButtonState:%2"}.arg(m_auto).arg(m_autoButtonState));
          check_button_color();     //avt 10/2/25
          return;
        }

        if (newTxMsgIdx == 9) {           //enable Tx
          debugToFile(QString{});
          debugToFile("setupCq      enable Tx");
          m_enableButtonNotify = false; //avt 1/23/24
          process_autoButton(true);
          ui->autoButton->setChecked(param0);
          m_autoButtonState = param0;   //avt 10/2/25
          m_enableButtonNotify = true; //avt 1/23/24
          //debugToFile(QString{"             m_auto:%1 autoButton m_autoButtonState:%2"}.arg(m_auto).arg(m_autoButtonState));
          check_button_color();     //avt 10/2/25
          return;
        }

        if (newTxMsgIdx == 12) {          //avt 12/31/21 halt tx
          debugToFile(QString{});
          debugToFile("setupCq      haltTx");
          m_enableButtonNotify = false; //avt 1/23/24
          on_stopTxButton_clicked();      //avt 12/31/21
          m_enableButtonNotify = true; //avt 1/23/24
          debugToFile(QString{"             m_auto:%1 autoButton m_autoButtonState:%2"}.arg(m_auto).arg(m_autoButtonState));
          return;                         //avt 1/25/22
        }

        if (newTxMsgIdx == 10) {            //change options
          ui->tx1->setEnabled(!param0);   //avt 10/26/21 set/clear skip grid msg
          if (param1 != m_send_RR73) on_txrb4_doubleClicked();  //avt 10/26/21 set/clear use of RR73 msg
          if (offset) {                     //avt 11/12/21 set offset frequency
            ui->TxFreqSpinBox->setValue(offset);    //avt 11/12/21
            ui->cbHoldTxFreq->setChecked(true);     //avt 11/13/21
            ui->cbHoldTxFreq->setEnabled(false);    //avt 11/13/21
          }
          m_bOffset = offset > 0;           //avt 11/13/21
          return;                           //avt 1/25/22
        }

        if (newTxMsgIdx == 11) {          //avt 12/31/21 enable monitoring
          if (!m_monitoring) on_monitorButton_clicked(true);        //avt 12/31/21
          return;                         //avt 1/25/22
        }

        if (newTxMsgIdx == 13) {          //avt 6/9/22 reset watchdog timer
          tx_watchdog(false);
          return;
        }

        if (newTxMsgIdx == 14) {          //avt 2/1/24
          m_listenMode = param0;
          ui->txFirstCheckBox->setEnabled(!m_listenMode);
          ui->genStdMsgsPushButton->setEnabled(!m_listenMode);   //avt 2/2/24
          debugToFile(QString{"setup        listenMode:%1"}.arg(m_listenMode));  //avt 2/2/24
          return;
        }

        if (newTxMsgIdx == 255) {         //avt 1/1/21
          //do logging with explicit values that may be unrelated to current QSO
          auto const& parts = msg.split ('$');
          if (parts.size() != 4) {
            MessageBox::warning_message (this, tr ("Error"), tr ("parts != 4"));
          }

          //                  call,     grid,     band,     mode,     ADIF);
          if (!m_logBook.add (parts[0], parts[1], parts[2], parts[3], check.toUtf8())) {
            MessageBox::warning_message (this, tr ("Log file error"), tr ("Cannot open \"%1\"").arg (m_logBook.path ()));
          }
          
          logIncremental(parts[0], check);

          // Log to N1MM Logger
          if (m_config.broadcast_to_n1mm () && m_config.valid_n1mm_info ()) {
            QUdpSocket sock;
            QHostAddress target;
            QString resolve_error;
            if (!resolve_udp_target (m_config.n1mm_server_name (), &target, &resolve_error))
              {
                MessageBox::warning_message (this, tr ("Error sending log to N1MM"),
                                             tr ("Unable to resolve \"%1\": %2")
                                               .arg (m_config.n1mm_server_name (), resolve_error));
              }
            else if (-1 == sock.writeDatagram (check.toUtf8() + " <eor>", target, m_config.n1mm_server_port ())) {
              MessageBox::warning_message (this, tr ("Error sending log to N1MM"), tr ("Write returned \"%1\"").arg (sock.errorString ()));
            }
          }
          return;                         //avt 1/25/22
        }
      }
      else      //special cmd
      {
        externalCtrlTimer.stop(); //avt 12/16/21
        m_externalCtrl = false;    //avt 12/4/20 de-init, WSJT-X back to normal operation
        initExternalCtrl();
        debugToFile(QString{});
        debugToFile("setupCq      Controller terminated");
        showStatusMessage("Controller terminated");
        return;
      }
    });

  m_autoSpotEnabled = m_settings
    ? m_settings->value(QStringLiteral("AutoSpotEnabled"), m_config.auto_spot_enabled()).toBool()
    : m_config.auto_spot_enabled();
  if (ui && ui->autoCQButton)
    {
      if (auto * controls = ui->autoCQButton->parentWidget())
        {
          if (auto * grid = qobject_cast<QGridLayout *> (controls->layout()))
            {
              m_autoSpotCheckBox = new QCheckBox {tr("AutoSpot"), controls};
              m_autoSpotCheckBox->setToolTip(
                tr("Invia spot al cluster configurato dopo il log QSO (73 confermato)."));
              m_autoSpotCheckBox->setChecked(m_autoSpotEnabled);
              grid->addWidget(m_autoSpotCheckBox, 0, 13);
              connect(m_autoSpotCheckBox, &QCheckBox::toggled, this, [this](bool enabled) {
                  setAutoSpotEnabled(enabled, false);
                });
            }
        }
    }

  // Optional remote WS + HTTP control:
  // 1) env var override (FT2_REMOTE_*)
  // 2) Settings -> General -> Experimental Remote Dashboard.
  if (!m_embeddedShellMode)
  {
    QString wsPortText = m_env.value("FT2_REMOTE_WS_PORT").trimmed();
    QString httpPortText = m_env.value("FT2_REMOTE_HTTP_PORT").trimmed();
    QString bindText = m_env.value("FT2_REMOTE_WS_BIND").trimmed();
    QString authUser = m_env.value("FT2_REMOTE_WS_USER").trimmed();
    QString authToken = m_env.value("FT2_REMOTE_WS_TOKEN").trimmed();

    if (wsPortText.isEmpty())
      {
        bool remoteEnabled = m_config.remote_web_enabled();
        int remoteHttpPort = static_cast<int> (m_config.remote_http_port());
        QString remoteBind = m_config.remote_ws_bind().trimmed();
        QString remoteUser = m_config.remote_user().trimmed();
        QString remoteToken = m_config.remote_token();

        if (remoteUser.isEmpty())
          {
            remoteUser = QStringLiteral("admin");
          }

        if (remoteEnabled)
          {
            if (remoteHttpPort < 1025 || remoteHttpPort > 65535)
              {
                showStatusMessage(tr("Remote Web disabled: invalid configured HTTP port %1").arg(remoteHttpPort));
              }
            else
              {
                httpPortText = QString::number(remoteHttpPort);
                wsPortText = QString::number(remoteHttpPort - 1);
              }

            if (bindText.isEmpty())
              {
                bindText = remoteBind;
              }
            if (authToken.isEmpty())
              {
                authToken = remoteToken;
              }
            if (authUser.isEmpty())
              {
                authUser = remoteUser;
              }
          }
      }

    bool wsPortOk {false};
    auto const wsPortRaw = wsPortText.toUInt(&wsPortOk);
    auto const wsPort = static_cast<quint16>(wsPortRaw & 0xFFFFu);

    if (wsPortOk && wsPort > 0)
      {
        QHostAddress bindAddress;
        if (bindText.isEmpty())
          {
            bindText = QStringLiteral("0.0.0.0");
          }
        auto const bindLower = bindText.toLower();
        if (bindLower.isEmpty() ||
            0 == bindLower.compare("any", Qt::CaseInsensitive) ||
            0 == bindLower.compare("any4", Qt::CaseInsensitive) ||
            0 == bindLower.compare("*", Qt::CaseInsensitive) ||
            0 == bindLower.compare("0.0.0.0", Qt::CaseInsensitive))
          {
            bindAddress = QHostAddress::AnyIPv4;
          }
        else if (0 == bindLower.compare("any6", Qt::CaseInsensitive) ||
                 0 == bindLower.compare("::", Qt::CaseInsensitive))
          {
            bindAddress = QHostAddress::AnyIPv6;
          }
        else if (0 == bindLower.compare("localhost", Qt::CaseInsensitive))
          {
            bindAddress = QHostAddress::LocalHost;
          }
        else if (!bindAddress.setAddress(bindText))
          {
            showStatusMessage(tr("Remote WS: invalid FT2_REMOTE_WS_BIND=\"%1\" (using 0.0.0.0)").arg(bindText));
            bindAddress = QHostAddress::AnyIPv4;
          }

        authToken = authToken.trimmed();
        bool const remoteExposed = !(bindAddress.isLoopback()
                                     || bindAddress == QHostAddress::LocalHost
                                     || bindAddress == QHostAddress::LocalHostIPv6);
        bool remoteServerAllowed {true};
        if (remoteExposed && authToken.isEmpty())
          {
            showStatusMessage(tr("Remote Web disabled: non-loopback bind requires token authentication."));
            remoteServerAllowed = false;
          }
        else if (remoteExposed && authToken.size() < 12)
          {
            showStatusMessage(tr("Remote Web disabled: token must be at least 12 characters on LAN/WAN bind."));
            remoteServerAllowed = false;
          }

        if (remoteServerAllowed)
          {
            m_remoteCommandServer = new RemoteCommandServer {this};
            m_remoteCommandServer->setRuntimeStateProvider([this] {
                RemoteCommandServer::RuntimeState state;
                state.mode = m_mode;
                QString bandText;
                if (ui && ui->bandComboBox)
                  {
                    bandText = ui->bandComboBox->currentText().trimmed();
                  }
                if (bandText.isEmpty())
                  {
                    bandText = m_currentBand.trimmed();
                  }
                state.band = bandText;
                state.dialFrequencyHz = static_cast<qint64>(m_freqNominal);
                state.rxFrequencyHz = ui && ui->RxFreqSpinBox ? ui->RxFreqSpinBox->value() : 0;
                state.txFrequencyHz = ui && ui->TxFreqSpinBox ? ui->TxFreqSpinBox->value() : 0;
                state.periodMs = qMax<qint64>(1, qRound64(m_TRperiod * 1000.0));
                state.txEnabled = m_auto;
                state.autoCqEnabled = m_autoCQ;
                state.autoSpotEnabled = m_autoSpotEnabled;
                state.asyncL2Enabled = ui && ui->cbAsyncDecode && ui->cbAsyncDecode->isChecked();
                state.dualCarrierEnabled = ui && ui->cbDualCarrier && ui->cbDualCarrier->isChecked();
                state.alt12Enabled = ui && ui->cbAutoTogglePeriod && ui->cbAutoTogglePeriod->isChecked();
                state.manualTxEnabled = ui && ui->cbManualTx && ui->cbManualTx->isChecked();
                state.speedyContestEnabled = ui && ui->cbSpeedyContest && ui->cbSpeedyContest->isChecked();
                state.digitalMorseEnabled = ui && ui->cbDigitalMorse && ui->cbDigitalMorse->isChecked();
                state.quickQsoEnabled = ui && ui->btnQuickQSO && ui->btnQuickQSO->isChecked();
                state.ft2QsoMessageCount = ft2QsoMessageCount(m_ft2QsoMessageProfile);
                state.asyncSnrDb = (m_mode == "FT2" && m_asyncVis) ? m_asyncVis->snr() : -99;
                state.uiLanguage = m_settings ? m_settings->value(QStringLiteral("UILanguage")).toString().trimmed() : QString {};
                if (state.uiLanguage.isEmpty())
                  {
                    state.uiLanguage = QLocale::system().name();
                  }
                if (state.uiLanguage.isEmpty())
                  {
                    state.uiLanguage = QStringLiteral("en");
                  }
                state.monitoring = m_monitoring;
                state.transmitting = m_transmitting;
                state.myCall = m_config.my_callsign();
                state.dxCall = ui && ui->dxCallEntry ? ui->dxCallEntry->text().trimmed().toUpper() : QString {};
                state.nowUtcMs = ntpCorrectedCurrentMSecsSinceEpoch();
                return state;
              });

            bool guardOk {false};
            auto const guardMs = m_env.value("FT2_REMOTE_GUARD_PRE_MS", "300").toInt(&guardOk);
            if (guardOk)
              {
                m_remoteCommandServer->setGuardPreMs(guardMs);
              }

            bool ageOk {false};
            auto const maxAgeMs = m_env.value("FT2_REMOTE_MAX_AGE_MS", "7500").toInt(&ageOk);
            if (ageOk)
              {
                m_remoteCommandServer->setMaxCommandAgeMs(maxAgeMs);
              }

            m_remoteCommandServer->setAuthUser(authUser);
            if (!authToken.isEmpty())
              {
                m_remoteCommandServer->setAuthToken(authToken);
              }

            quint16 httpPort {0};
            if (!httpPortText.isEmpty())
              {
                bool httpPortOk {false};
                auto const httpPortRaw = httpPortText.toUInt(&httpPortOk);
                if (httpPortOk && httpPortRaw <= 65535u)
                  {
                    httpPort = static_cast<quint16>(httpPortRaw);
                  }
                else
                  {
                    showStatusMessage(tr("Remote HTTP: invalid FT2_REMOTE_HTTP_PORT=\"%1\" (using default ws+1)")
                                      .arg(httpPortText));
                  }
              }

            connect(m_remoteCommandServer, &RemoteCommandServer::selectCallerDue,
                    this, &MainWindow::onRemoteSelectCallerDue);
            connect(m_remoteCommandServer, &RemoteCommandServer::setModeRequested,
                    this, &MainWindow::onRemoteSetModeRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setBandRequested,
                    this, &MainWindow::onRemoteSetBandRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setDialFrequencyRequested,
                    this, &MainWindow::onRemoteSetDialFrequencyRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setRxFrequencyRequested,
                    this, &MainWindow::onRemoteSetRxFrequencyRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setTxFrequencyRequested,
                    this, &MainWindow::onRemoteSetTxFrequencyRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setTxEnabledRequested,
                    this, &MainWindow::onRemoteSetTxEnabledRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setAutoCqRequested,
                    this, &MainWindow::onRemoteSetAutoCqRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setAutoSpotRequested,
                    this, &MainWindow::onRemoteSetAutoSpotRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setMonitoringRequested,
                    this, &MainWindow::onRemoteSetMonitoringRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setAsyncL2Requested,
                    this, &MainWindow::onRemoteSetAsyncL2Requested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setDualCarrierRequested,
                    this, &MainWindow::onRemoteSetDualCarrierRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setAlt12Requested,
                    this, &MainWindow::onRemoteSetAlt12Requested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setManualTxRequested,
                    this, &MainWindow::onRemoteSetManualTxRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setSpeedyContestRequested,
                    this, &MainWindow::onRemoteSetSpeedyContestRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setDigitalMorseRequested,
                    this, &MainWindow::onRemoteSetDigitalMorseRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setQuickQsoRequested,
                    this, &MainWindow::onRemoteSetQuickQsoRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::setFt2QsoMessageCountRequested,
                    this, &MainWindow::onRemoteSetFt2QsoMessageCountRequested);
            connect(m_remoteCommandServer, &RemoteCommandServer::waterfallStreamingChanged,
                    this, &MainWindow::onRemoteWaterfallStreamingChanged);
            connect(m_remoteCommandServer, &RemoteCommandServer::logMessage, this,
                    [this] (QString const& message) { showStatusMessage(message); });

            m_remoteWaterfallStreamingEnabled = m_remoteCommandServer->waterfallEnabled();

            if (!m_remoteCommandServer->start(wsPort, bindAddress, httpPort))
              {
                showStatusMessage(tr("Remote WS disabled: failed to bind %1:%2")
                                    .arg(bindAddress.toString())
                                    .arg(wsPort));
              }
            else if (remoteExposed)
              {
                showStatusMessage(tr("Remote Web notice: traffic is plain HTTP/WS. Use only trusted LAN/VPN or a TLS reverse proxy."));
              }
          }
      }
    else if (!wsPortText.isEmpty())
      {
        showStatusMessage(tr("Remote WS disabled: invalid FT2_REMOTE_WS_PORT=\"%1\"").arg(wsPortText));
      }
  }

