void MainWindow::invalidate_frequencies_filter ()
{
  // every interval, invalidate the frequency filter, so that if any
  // working frequency goes in/out of scope, we pick it up.
  m_config.frequencies ()->filter_refresh ();
  ui->bandComboBox->update ();
}

void MainWindow::on_the_minute ()
{
  if (minuteTimer.isSingleShot ())
    {
      minuteTimer.setSingleShot (false);
      minuteTimer.start (60 * 1000); // run free
    }
  else
    {
        auto const& ms_error = ms_minute_error ();
        if (qAbs (ms_error) > 1000) // keep drift within +-1s
        {
          minuteTimer.setSingleShot (true);
          minuteTimer.start (ms_error + 60 * 1000);
        }
    }

  if (m_config.watchdog () && m_mode!="WSPR" && m_mode!="FST4W") {
    if (m_idleMinutes < m_config.watchdog ()) ++m_idleMinutes;
    update_watchdog_label ();
  } else {
    tx_watchdog (false);
  }
  update_foxLogWindow_rate(); // update the rate on the window
  if ((!verified && ui->labDXped->isVisible()) or !ui->labDXped->text().contains("Hound"))
    ui->labDXped->setStyleSheet("QLabel {background-color: red; color: white;}");
  verified = false;
  if(!m_transmitting && m_mode=="FT8" && (QDateTime::currentMSecsSinceEpoch()-m_mslastTX) > 120000) m_lapmyc=0;
}

//--------------------------------------------------- MainWindow destructor
MainWindow::~MainWindow()
{
  m_valid = false;
  m_dataSinkShuttingDown = true;
  if (m_ft2DecodeWorker) {
    m_ft2DecodeWorker->beginShutdown ();
  }
  if (m_ft8DecodeWorker) {
    m_ft8DecodeWorker->beginShutdown ();
  }
  QObject::disconnect (m_applicationStateChangedConnection);
  m_applicationStateChangedConnection = {};
  QObject::disconnect (m_detectorFramesWrittenConnection);
  m_detectorFramesWrittenConnection = {};
  QObject::disconnect (m_tciFramesWrittenConnection);
  m_tciFramesWrittenConnection = {};
  QCoreApplication::removePostedEvents (this, QEvent::MetaCall);
  Q_EMIT suspendAudioInputStream ();
  m_asyncDecodeTimer.stop ();
  stop_worker_thread (m_ft2DecodeThread, "FT2");
  stop_worker_thread (m_ft4DecodeThread, "FT4");
  stop_worker_thread (m_fst4DecodeThread, "FST4");
  stop_worker_thread (m_ft8DecodeThread, "FT8");
  stop_worker_thread (m_jt9FastDecodeThread, "JT9Fast");
  stop_worker_thread (m_q65DecodeThread, "Q65");
  stop_worker_thread (m_msk144DecodeThread, "MSK144");
  stop_worker_thread (m_legacyJtDecodeThread, "LegacyJT");
  stop_worker_thread (m_wsprDecodeThread, "WSPR");

  if(m_astroWidget) m_astroWidget.reset ();
  if(m_QSYMessageCreatorWidget) m_QSYMessageCreatorWidget.reset ();
  if(m_QSYMessageWidget) m_QSYMessageWidget.reset ();
  if(m_qsymonitorWidget) m_qsymonitorWidget.reset ();
  if (auto * bar = statusBar ())
    {
      auto detach_status_widget = [bar] (QWidget& widget)
        {
          if (widget.parentWidget () == bar)
            {
              bar->removeWidget (&widget);
            }
          widget.hide ();
          widget.setParent (nullptr);
        };

      detach_status_widget (tx_status_label);
      detach_status_widget (config_label);
      detach_status_widget (mode_label);
      detach_status_widget (last_tx_label);
      detach_status_widget (auto_tx_label);
      detach_status_widget (band_hopping_label);
      detach_status_widget (ndecodes_label);
      detach_status_widget (dt_correction_label);
      detach_status_widget (decodium_cert_label);
      detach_status_widget (progressBar);
      detach_status_widget (watchdog_label);
      detach_status_widget (ntp_checkbox);
      detach_status_widget (ntp_server_edit);
      detach_status_widget (ntp_status_label);
    }
  m_optimizingProgress.hide ();
  m_optimizingProgress.setParent (nullptr);
  auto fname {QDir::toNativeSeparators(m_config.writeable_data_dir ().absoluteFilePath ("decodium_wisdom.dat"))};
  fftwf_export_wisdom_to_filename (fname.toLocal8Bit ());
  m_audioThread.quit ();
  wait_for_thread_with_event_pump (m_audioThread, -1);
  remove_child_from_event_filter (this);
  memset(ipc_qmap,0,4096);         //Zero all of QMAP shared memory
}

