void MainWindow::legacyShutdownForEmbedding()
{
  if (upLotw) {
    disconnect(upLotw, nullptr, this, nullptr);
    if (upLotw->state() != QProcess::NotRunning) {
      upLotw->terminate();
      if (!upLotw->waitForFinished(500)) {
        upLotw->kill();
        upLotw->waitForFinished(1000);
      }
    }
    upLotw->close();
    delete upLotw;
    upLotw = nullptr;
  }

  m_logbookRead = true;
  close();
}

