void MainWindow::on_DecodeButton_clicked (bool /* checked */) //Decode request
{
  if(m_mode=="MSK144") {
    ui->DecodeButton->setChecked(false);
  } else {
    if(m_mode!="WSPR" && !m_decoderBusy) {
      m_manualDecode=true;
      dec_data.params.newdat=0;
      dec_data.params.nagain=1;
      decode();
    }
  }
}

void MainWindow::freezeDecode(int n)                          //freezeDecode()
{
  if((n%100)==2) {
    if(m_mode=="FST4" and m_config.single_decode() and ui->sbFtol->value()>10) ui->sbFtol->setValue(10);
    on_DecodeButton_clicked (true);
  }
}

void MainWindow::on_ClrAvgButton_clicked()
{
  m_nclearave=1;
  if(m_mode=="Echo") {
    decodium::legacy::echo_plot_state ().nsum = 0;
    m_echoGraph->clearAvg();
    m_wideGraph->restartTotalPower();
  } else {
    if(m_msgAvgWidget != NULL) {
      if(m_msgAvgWidget->isVisible()) m_msgAvgWidget->displayAvg("");
    }
    if(m_mode=="Q65") ndecodes_label.setText("0  0");
  }
}

void MainWindow::msgAvgDecode2()
{
  on_DecodeButton_clicked (true);
}

void MainWindow::decode()                                       //decode()
{
  bool queueEmbeddedFt8FullSlot = false;

  if (m_decoderBusy) {
    bool const ft2MayPreempt =
        (m_mode == "FT2"
         && m_ft2DecodePending
         && m_ft2DecodeWorker
         && m_ft2DecodeThread.isRunning ()
         && !m_diskData
         && m_dateTimeSeqStart.isValid ());

    bool const ft8MayPreempt =
        (m_mode == "FT8"
         && m_embeddedShellMode
         && !m_multithreadFT8
         && m_ft8DecodePending
         && m_ft8DecodeWorker
         && m_ft8DecodeThread.isRunning ()
         && !m_diskData
         && m_ihsym == m_hsymStop
         && m_dateTimeSeqStart.isValid ());

    // Live FT8 must not publish one slot late. The worker has its own live
    // time budget, so if it still overruns a boundary this decode is stale and
    // the current slot takes priority.
    queueEmbeddedFt8FullSlot = false;

    if (!ft2MayPreempt && !ft8MayPreempt && !queueEmbeddedFt8FullSlot) {
      return;                          //Don't start decoder if it's already busy.
    }

    if (ft2MayPreempt) {
      auto const t = m_dateTimeSeqStart.time ();
      int pendingUtc = t.hour () * 100 + t.minute ();
      if (m_TRperiod < 60.)
        {
          pendingUtc = pendingUtc * 100 + t.second ();
        }
      if (pendingUtc == m_ft2DecodePendingUtc)
        {
          return;
        }

      cancelPendingInProcessDecode ();
    }

    if (ft8MayPreempt) {
      auto const t = m_dateTimeSeqStart.time ();
      int pendingUtc = t.hour () * 100 + t.minute ();
      if (m_TRperiod < 60.)
        {
          pendingUtc = pendingUtc * 100 + t.second ();
        }
      if (pendingUtc == m_ft8DecodePendingUtc)
        {
          return;
        }

      if (!queueEmbeddedFt8FullSlot)
        {
          cancelPendingInProcessDecode ();
        }
    }
  }
  m_fetched=0;
  QDateTime now = QDateTime::currentDateTimeUtc ();
  bool const cqOnlyDecodeRequested =
      ui && ui->cbCQonly && ui->cbCQonly->isVisible() && ui->cbCQonly->isChecked();
  bool const preferUniformCqDecode =
      cqOnlyDecodeRequested
      && !m_diskData
      && SpecOp::NONE == m_specOp
      && !m_transmitting
      && (m_mode == "FT8" || m_mode == "FT4" || m_mode == "FT2")
      && (m_QSOProgress <= 1 || m_hisCall.trimmed().isEmpty());

  if( m_dateTimeLastTX.isValid () ) {
    qint64 isecs_since_tx = m_dateTimeLastTX.secsTo(now);
    dec_data.params.lapcqonly= (isecs_since_tx > 300); 
  } else { 
    m_dateTimeLastTX = now.addSecs(-900);
    dec_data.params.lapcqonly=true;
  }
  if(m_diskData) {
    dec_data.params.lapcqonly=false;
  } else {
    dec_data.params.yymmdd=-1;
  }
  if (preferUniformCqDecode) {
    dec_data.params.lapcqonly = true;
  }
  if(!m_dataAvailable or m_TRperiod==0.0) return;
  ui->DecodeButton->setChecked (true);
  if(!dec_data.params.nagain && m_diskData && m_TRperiod >= 60.) {
    dec_data.params.nutc=dec_data.params.nutc/100;
  }
  if(dec_data.params.nagain==0 && dec_data.params.newdat==1 && (!m_diskData)) {
    // m_dateTimeSeqStart already set by dataSink() before calling decode()
    auto t = m_dateTimeSeqStart.time ();
    dec_data.params.nutc = t.hour () * 100 + t.minute ();
    if (m_TRperiod < 60.)
      {
        dec_data.params.nutc = dec_data.params.nutc * 100 + t.second ();
      }
  }

  if(m_nPick==1 and !m_diskData) {
    QDateTime t=QDateTime::currentDateTimeUtc();
    int ihr=t.toString("hh").toInt();
    int imin=t.toString("mm").toInt();
    int isec=t.toString("ss").toInt();
    isec=isec - fmod(double(isec),m_TRperiod);
    dec_data.params.nutc=10000*ihr + 100*imin + isec;
  }
  if(m_nPick==2) dec_data.params.nutc=m_nutc0;
  dec_data.params.nQSOProgress = m_QSOProgress;
  dec_data.params.nfqso=m_wideGraph->rxFreq();
  dec_data.params.nftx = ui->TxFreqSpinBox->value ();
  qint32 depth {m_ndepth};
  if (!m_embeddedShellMode) {
    if (!ui->actionInclude_averaging->isVisible ()) depth &= ~16;
    if (!ui->actionInclude_correlation->isVisible ()) depth &= ~32;
    if (!ui->actionEnable_AP_DXcall->isVisible ()) depth &= ~64;
    if (!ui->actionAuto_Clear_Avg->isVisible()) depth &= ~128;
  }
  dec_data.params.ndepth=depth;
  dec_data.params.n2pass=1;
  if(m_config.twoPass()) dec_data.params.n2pass=2;
  dec_data.params.nranera=m_config.ntrials();
  dec_data.params.naggressive=m_config.aggressive();
  dec_data.params.nrobust=0;
  dec_data.params.ndiskdat=0;
  if(m_diskData) dec_data.params.ndiskdat=1;
  dec_data.params.nfa=m_wideGraph->nStartFreq();
  dec_data.params.nfSplit=m_wideGraph->Fmin();  // Not used any more?
  if(dec_data.params.nfSplit==8) dec_data.params.nfSplit=1;

  dec_data.params.nfb=effectiveDecodeFmax();
  if((m_mode=="FT8" or m_mode=="FT2") and SpecOp::HOUND==m_specOp and !ui->cbRxAll->isChecked() and
     !m_config.superFox()) dec_data.params.nfb=1000;
  if((m_mode=="FT8" or m_mode=="FT2") and SpecOp::FOX == m_specOp ) dec_data.params.nfqso=200;
  if (preferUniformCqDecode) {
    int const searchLow = qBound (0, int (dec_data.params.nfa), 5000);
    int const searchHigh = qBound (searchLow + 1, int (dec_data.params.nfb), 5000);
    dec_data.params.nfqso = qBound (searchLow, (searchLow + searchHigh) / 2, searchHigh);
  }
  dec_data.params.b_even_seq=(dec_data.params.nutc%10)==0;
  dec_data.params.b_superfox=(m_config.superFox() and (SpecOp::FOX == m_specOp or SpecOp::HOUND == m_specOp));
  if(m_mode=="FT8" and dec_data.params.b_superfox and dec_data.params.b_even_seq and m_ihsym<50) return;

  dec_data.params.ntol=ui->sbFtol->value ();
  if(m_mode=="FST4") {
    dec_data.params.ntol=ui->sbFtol->value();
    if(m_config.single_decode()) {
      dec_data.params.nfa=m_wideGraph->rxFreq() - ui->sbFtol->value();
      dec_data.params.nfb=m_wideGraph->rxFreq() + ui->sbFtol->value();
    } else {
      dec_data.params.nfa=ui->sbF_Low->value();
      dec_data.params.nfb=ui->sbF_High->value();
    }
  }
  if(m_mode=="FST4W") dec_data.params.ntol=ui->sbFST4W_FTol->value();
  if(dec_data.params.nutc < m_nutc0) m_RxLog = 1;       //Date and Time to file "ALL.TXT".
  if(dec_data.params.newdat==1 and !m_diskData) m_nutc0=dec_data.params.nutc;
  dec_data.params.ntxmode=9;
  dec_data.params.nmode=9;
  if(m_mode=="JT65") dec_data.params.nmode=65;
  if(m_mode=="JT65") dec_data.params.ljt65apon = ui->actionEnable_AP_JT65->isVisible () &&
      ui->actionEnable_AP_JT65->isChecked ();
  if(m_mode=="Q65") dec_data.params.nmode=66;
  if(m_mode=="Q65") dec_data.params.ntxmode=66;
  if(m_mode=="JT4") {
    dec_data.params.nmode=4;
    dec_data.params.ntxmode=4;
  }
  if(m_mode=="FT8") dec_data.params.nmode=8;
  if(m_mode=="FT8") dec_data.params.lft8apon = ui->actionEnable_AP_FT8->isVisible () &&
      ui->actionEnable_AP_FT8->isChecked ();
  if(m_mode=="FT8") dec_data.params.napwid=50;
  if(m_mode=="FT8" && preferUniformCqDecode) {
    dec_data.params.napwid = qBound (50, int (dec_data.params.nfb) - int (dec_data.params.nfa), 5000);
  }
  if(m_mode=="FT2") {
    dec_data.params.nmode=2;
    m_BestCQpriority="";
  }
  if(m_mode=="FT4") {
    dec_data.params.nmode=5;
    m_BestCQpriority="";
  }
  if(m_mode=="FST4") dec_data.params.nmode=240;
  if(m_mode=="FST4W") dec_data.params.nmode=241;
  dec_data.params.ntxmode=dec_data.params.nmode;   // Is this used any more?
  dec_data.params.ntrperiod=m_TRperiod;
  dec_data.params.nsubmode=m_nSubMode;
  dec_data.params.minw=0;
  dec_data.params.nclearave=m_nclearave;
  if(m_nclearave!=0) {
    QFile f(m_config.temp_dir ().absoluteFilePath ("avemsg.txt"));
    f.remove();
  }
  dec_data.params.dttol=m_DTtol;
  dec_data.params.emedelay=0.0;
  if(m_config.decode_at_52s()) dec_data.params.emedelay=2.5;
  dec_data.params.minSync=ui->syncSpinBox->isVisible () ? m_minSync : 0;
  dec_data.params.nexp_decode=int(m_specOp);
  if(dec_data.params.nexp_decode==5) dec_data.params.nexp_decode=1;  //NA VHF, WW Digi, ARRL Digi contests
  if(dec_data.params.nexp_decode==8) dec_data.params.nexp_decode=1;  //and Q65 Pileup all use 4-character
  if(dec_data.params.nexp_decode==9) dec_data.params.nexp_decode=1;  //grid exchange
  if(m_config.single_decode()) dec_data.params.nexp_decode += 32;
  if(m_config.enable_VHF_features()) dec_data.params.nexp_decode += 64;
  if(m_mode.startsWith("FST4")) dec_data.params.nexp_decode += 256*(ui->sbNB->value()+3);
  dec_data.params.max_drift=ui->sbMaxDrift->value();
  QString hisGrid;
  hisGrid=ui->dxGridEntry->text ();
  QString hisCall;
  hisCall=ui->dxCallEntry->text ();
    
  if(m_mode=="FT8" && m_multithreadFT8)
  {
    //FT8 block of parameters for multithreaded FT8 decoder
    dec_data.params.nstophint = 0;  // stophint should be false to avoid truncating decode process
    dec_data.params.nQSOProgress = m_QSOProgress;
    dec_data.params.nftx = ui->TxFreqSpinBox->value ();
    if(m_freqNominal < 30000000) dec_data.params.napwid=5; // FT8AP decoding bandwidth for 'mycall hiscall ???' and RRR,RR73,73 messages
    else if(m_freqNominal < 100000000) dec_data.params.napwid=15;
    else dec_data.params.napwid=50;
    dec_data.params.nmt=m_ft8threads;
    dec_data.params.ncandthin=m_ncandthin;
    dec_data.params.ndtcenter=0;  // ft8mod was 100 * ui->DTCenterSpinBox->value();
    if (m_ihsym==m_earlyDecode or m_ihsym==m_earlyDecode2) {
      dec_data.params.nft8cycles=2;
    } else {
      dec_data.params.nft8cycles=m_nFT8Cycles;
    }
    if(m_houndMode) { dec_data.params.nft8rxfsens=1; } else { dec_data.params.nft8rxfsens=m_nFT8RXfSens; }
    if(m_ft8Sensitivity==1) dec_data.params.lft8lowth=false;
    else  dec_data.params.lft8lowth=true;
    if(m_ft8Sensitivity==3) dec_data.params.lft8subpass=true;
    else dec_data.params.lft8subpass=false;
    dec_data.params.ltxing=(m_auto && (QDateTime::currentMSecsSinceEpoch()-m_mslastTX) < 26000) ? 1 : 0;  // ft8mdwas ( m_enableTx and jtdxTime etc.
    dec_data.params.lhideft8dupes=ui->actionHide_FT8_dupe_messages->isChecked() ? 1 : 0; //ft8md ui->actionHide_FT8_dupe_messages->isChecked() ? 1 : 0;
    dec_data.params.lhound=m_houndMode ? 1 : 0;
    dec_data.params.lcommonft8b=m_commonFT8b;    
    m_bMyCallStd=stdCall(m_config.my_callsign ()); //ft8md
    m_bHisCallStd=stdCall(m_hisCall); //ft8md
    dec_data.params.lmycallstd=m_bMyCallStd;
    dec_data.params.lhiscallstd=m_bHisCallStd;
    dec_data.params.lapmyc=m_lapmyc;
    dec_data.params.lmodechanged=false; // m_modeChanged ? 1 : 0; m_modeChanged=false;
    dec_data.params.lbandchanged=m_band_changed ? 1 : 0; // m_band_changed=false;
    dec_data.params.lmultinst=m_multInst ? 1 : 0;
    dec_data.params.lskiptx1=m_skipTx1 ? 1 : 0;
    dec_data.params.nlasttx=m_nlasttx;
    //ft8md dec_data.params.lforcesync=ui->syncButton->isChecked() && m_mode=="FT8";
    dec_data.params.ndecoderstart=m_ft8DecoderStart;
    dec_data.params.nsecbandchanged=m_nsecBandChanged; m_nsecBandChanged=0;
    dec_data.params.nhint=m_hint ? 1 : 0;
    dec_data.params.ndelay=m_delay;
    dec_data.params.nfqso=m_wideGraph->rxFreq();
    dec_data.params.ndepth=m_ndepth;
    qDebug() << "[DEPTHDBG] FT8-MT set: m_ndepth=" << m_ndepth
             << " ndepth=" << dec_data.params.ndepth
             << " ihsym=" << m_ihsym
             << " early=" << m_earlyDecode << " early2=" << m_earlyDecode2;
    dec_data.params.nranera=m_config.ntrials();
    dec_data.params.lmultift8=m_multithreadFT8; //ft8md
    dec_data.params.ntrials10=0; //ft8md was =m_config.ntrials10();
    dec_data.params.ntrialsrxf10=0; //ft8md was m_config.ntrialsrxf10();
    dec_data.params.nprepass=4; //ft8md was m_config.npreampass();
    dec_data.params.naggressive=1; //ft8md was m_config.aggressive();
    dec_data.params.nharmonicsdepth=0;  //ft8md was m_config.harmonicsdepth();
    dec_data.params.ntopfreq65=3000; //ft8md was m_config.ntopfreq65();
    dec_data.params.nsdecatt=1; //ft8md was m_config.nsingdecatt();
    dec_data.params.fmaskact=true; //ft8md was m_config.fmaskact();
    if (m_ihsym==m_earlyDecode or m_ihsym==m_earlyDecode2 or (m_specOp==SpecOp::HOUND && m_config.superFox())) {
      dec_data.params.lmultift8 = false; // use the standard FT8 decoder for early decoding step
      if (m_ihsym==m_earlyDecode2) dec_data.params.ndepth=2;
      qDebug() << "[DEPTHDBG] FT8-MT EARLY override: lmultift8=false ndepth=" << dec_data.params.ndepth;
    }
    dec_data.params.ndiskdat=0;
    if(m_diskData) dec_data.params.ndiskdat=1;
    dec_data.params.nfa=m_wideGraph->nStartFreq();
    dec_data.params.nfSplit=m_wideGraph->Fmin();
    dec_data.params.nfb=effectiveDecodeFmax();
    dec_data.params.ntol=50; // this value is not being used
    dec_data.params.ntrperiod=int(m_TRperiod);
    dec_data.params.lwidedxcsearch=m_FT8WideDxCallSearch ? 1 : 0;
  }
  ::memcpy(dec_data.params.datetime, m_dateTime.toLatin1()+"    ", sizeof dec_data.params.datetime);
  ::memcpy(dec_data.params.mycall, (m_config.my_callsign()+"            ").toLatin1(),12);
  
  ::memcpy(dec_data.params.mybcall, (Radio::base_callsign(m_config.my_callsign())+"            ").toLatin1(),12);
  ::memcpy(dec_data.params.hiscall,(hisCall+"            ").toLatin1(),12);
  if(hisCall.length()<3) { 
    hisCall.clear();
    ::memcpy(dec_data.params.hisbcall,(hisCall+"            ").toLatin1(),12); 
  } else {
    ::memcpy(dec_data.params.hisbcall,(Radio::base_callsign(hisCall)+"            ").toLatin1(),12);
  }
  ::memcpy(dec_data.params.hisgrid,(hisGrid+"      ").toLatin1(),6);    
  ::memcpy(dec_data.params.mygrid, (m_config.my_grid()+"      ").toLatin1(),6);
  
  if(!hisCall.isEmpty() && !m_auto && hisCall != m_lastloggedcall) dec_data.params.lenabledxcsearch=true;  //ft8md was && !m_enableTx
  else dec_data.params.lenabledxcsearch=false;

  if(m_mode=="MSK144" or m_bFast9) {
        float t0=m_t0;
        float t1=m_t1;
        QCoreApplication::processEvents (QEventLoop::ExcludeUserInputEvents); // Update the waterfall
        if(m_nPick > 0) {
          t0=m_t0Pick;
          t1=m_t1Pick;
        }
        narg[0]=dec_data.params.nutc;
        if(m_kdone>int(12000.0*m_TRperiod)) {
          m_kdone=int(12000.0*m_TRperiod);
        }
        narg[1]=m_kdone;
        narg[2]=m_nSubMode;
        narg[3]=dec_data.params.newdat;
        narg[4]=dec_data.params.minSync;
        narg[5]=m_nPick;
        narg[6]=1000.0*t0;
        narg[7]=1000.0*t1;
        narg[8]=2;                                //Max decode lines per decode attempt
        if(dec_data.params.minSync<0) narg[8]=50;
        if(m_mode=="JT9") narg[9]=102;            //Fast JT9
        if(m_mode=="MSK144") narg[9]=104;         //MSK144
        narg[10]=ui->RxFreqSpinBox->value();
        narg[11]=ui->sbFtol->value ();
        narg[12]=0;
        narg[13]=-1;
        narg[14]=m_config.aggressive();
        if (m_mode == "MSK144") {
          requestInProcessMsk144Decode ();
        } else {
          requestInProcessJt9FastDecode ();
        }
      } else {
        if (queueEmbeddedFt8FullSlot && m_mode == "FT8") {
          queueInProcessFt8Decode ();
        } else {
          requestSubprocessDecodeStart (m_ihsym);
        }
      }
  if((m_mode=="FT2" or m_mode=="FT4" or (m_mode=="FT8" and m_ihsym==41) or m_diskData) and
     m_ActiveStationsWidget != NULL) {
    if(m_mode!="Q65") m_ActiveStationsWidget->erase();  //TEMP
  }
}

// ── ASYMX unified dedup: 5s window, best SNR wins ──────────────────────
bool MainWindow::isDuplicateDecode(QString const& message)
{
  qint64 now = QDateTime::currentMSecsSinceEpoch();

  // Purge expired entries every 2s
  if (now - m_decodeDedupLastPurge > 2000) {
    for (auto it = m_decodeDedup.begin(); it != m_decodeDedup.end(); ) {
      if (now - it.value().msec > 5000) it = m_decodeDedup.erase(it);
      else ++it;
    }
    m_decodeDedupLastPurge = now;
  }

  // Key from payload (robust against variable spacing / packed rows).
  QString key = canonical_decode_payload_for_dedupe (message, m_mode);
  if (key.isEmpty()) return false;

  // Extract SNR using DecodedText parser (no fixed-column assumptions).
  DecodedText const decoded{message};
  int snr = decoded.snr();

  auto it = m_decodeDedup.find(key);
  if (it != m_decodeDedup.end()) {
    if (snr > it.value().snr) {
      // Better SNR — update entry but still skip display (already shown)
      it.value().snr = snr;
      it.value().msec = now;
    }
    return true;  // duplicate
  }

  m_decodeDedup.insert(key, {snr, now});
  return false;  // new decode
}

// ── ASYMX async confirmation filter ──────────────────────────────────
// Weak signals (SNR < -17) must be decoded 2x within 4.5s at similar freq
// to be displayed. Strong signals pass immediately. This eliminates
// virtually all false decodes with only ~1.5s extra latency for weak ones.
bool MainWindow::asyncConfirmDecode(QString const& message, int freq, int snr)
{
  qint64 now = QDateTime::currentMSecsSinceEpoch();

  // Purge expired pending decodes (> 5s old)
  for (auto it = m_asyncPending.begin(); it != m_asyncPending.end(); ) {
    if (now - it->msec > 5000) it = m_asyncPending.erase(it);
    else ++it;
  }

  // Strong signals: display immediately, no confirmation needed
  if (snr >= -19) return true;

  // Extract payload key robustly (no fixed-column assumptions).
  QString key = canonical_decode_payload_for_dedupe (message, m_mode);
  if (key.isEmpty()) return true;  // safety: let it through

  // Check if this matches a pending decode
  for (auto it = m_asyncPending.begin(); it != m_asyncPending.end(); ++it) {
    if (it->msg == key && abs(it->freq - freq) <= 10
        && (now - it->msec) <= 4500) {
      it->count++;
      if (it->count >= 2) {
        m_asyncPending.erase(it);  // confirmed, remove from pending
        return true;  // display it
      }
      it->msec = now;  // refresh timestamp
      return false;    // not yet confirmed
    }
  }

  // New weak decode: add to pending, don't display yet
  m_asyncPending.append({key, freq, snr, now, 1});
  return false;
}

void MainWindow::processFastDecodedRows (QStringList const& rows)
{
  float t,tmax=-99.0;
  dec_data.params.nagain=false;
  dec_data.params.ndiskdat=false;
  auto const activePartnerCall = (!m_hisCall.trimmed ().isEmpty ()
                                  ? m_hisCall
                                  : ui->dxCallEntry->text ()).trimmed ().toUpper ();
  auto const myCallUpper = m_config.my_callsign ().trimmed ().toUpper ();
  auto const myBaseUpper = m_baseCall.trimmed ().toUpper ();
  for (auto const& row : rows) {
    QString message = resolve_active_qso_placeholder_decode_line (
        row, myCallUpper, myBaseUpper, activePartnerCall);
    if(message.length()>80) message=message.left (80);
    if(narg[13]/8==narg[12]) message=message.trimmed().replace("<...>",m_calls);

//Left (Band activity) window
    DecodedText decodedtext {message.replace (QChar::LineFeed, "")};
    if(!m_bFastDone) {
      ui->decodedTextBrowser->displayDecodedText (decodedtext, m_config.my_callsign (), m_mode, m_config.DXCC (),
         m_logBook, m_currentBandPeriod, m_config.ppfx (), false, false, 0.0, false, -99, "", m_muted);
      if(m_position != 0) ui->decodedTextBrowser->horizontalScrollBar()->setValue(m_position);
    }

    t=message.mid(10,5).toFloat();
    if(t>tmax) {
      tmax=t;
      m_bDecoded=true;
    }
    postDecode (true, decodedtext);   //avt 9/30/25
    write_all("Rx",message);

    if(m_mode=="JT9" or m_mode=="MSK144") {
// find and extract any report for myCall
      bool stdMsg = decodedtext.report(m_baseCall,
                    Radio::base_callsign(ui->dxCallEntry->text()), m_rptRcvd);

// extract details and send to PSKreporter
      if (stdMsg) pskPost (decodedtext);
    }
    if (tmax >= 0.0) {
      if (m_bDXpedMode) dxpedAutoSequence (decodedtext);
      auto_sequence (decodedtext, ui->sbFtol->value (), ui->sbFtol->value ());
    }
  }
  m_startAnother=m_loopall;
  m_nPick=0;
  ui->DecodeButton->setChecked (false);
  m_bFastDone=false;
}

void::MainWindow::fast_decode_done()
{
  QStringList rows;
  rows.reserve (100);
  for (int i = 0; m_msg[i][0] && i < 100; ++i) {
    rows << QString::fromLatin1 (m_msg[i]);
    m_msg[i][0] = 0;
  }
  processFastDecodedRows (rows);
}

void MainWindow::decodeDone ()
{
  if(m_mode=="Q65") m_wideGraph->drawRed(0,0);
  if ("FST4W" == m_mode)
    {
      if (m_uploadWSPRSpots
          && m_config.is_transceiver_online ()) { // need working rig control
#if QT_VERSION >= QT_VERSION_CHECK (5, 15, 0)
        uploadTimer.start(QRandomGenerator::global ()->bounded (0, 20000)); // Upload delay
#else
        uploadTimer.start(20000 * qrand()/((double)RAND_MAX + 1.0)); // Upload delay
#endif
      }
    }
  auto tnow = QDateTime::currentDateTimeUtc ();
  double tdone = fmod(double(tnow.time().second()),m_TRperiod);
  int mswait;
  if( tdone < 0.5*m_TRperiod ) {
    mswait = 1000.0 * ( 0.6 * m_TRperiod - tdone );
  } else {
    mswait = 1000.0 * ( 1.6 * m_TRperiod - tdone );
  }
  m_bDecoded=m_nDecodes>0;
  if(!m_diskData and !m_saveAll) {
    if(m_saveDecoded and (m_nDecodes==0)) {
      killFileTimer.start(mswait); //Kill at 3/4 period
    }
  }

  dec_data.params.nagain=0;
  dec_data.params.ndiskdat=0;
  m_nclearave=0;
  ui->DecodeButton->setChecked (false);
  decodeBusy(false);
  m_RxLog=0;
  if(SpecOp::FOX == m_specOp) {
    houndCallers();
    if(ui->cbWorkDupes->isChecked()) QTimer::singleShot (5000, [=] {band_activity_cleared();});
  }

  bool const autoCqRxSequenceComplete =
      (m_mode != "FT8")
      || dec_data.params.nzhsym == 50
      || (m_mode == "FT8" && m_multithreadFT8 && (m_hsymStop == dec_data.params.nzhsym));

  // Auto CQ timeout is measured per real RX period, not per intermediate decode pass.
  // FT8 can run early/multi-stage decodes inside the same 15 s slot; counting every
  // decodeDone() call would abandon a caller too early (for example after only 2-3 TXs).
  // During deferred RR73/73 signoff, do not clear the QSO here: logging/retry is handled elsewhere.
  if (m_autoCQ && m_QSOProgress > CALLING && !m_diskData && autoCqRxSequenceComplete) {
    if (m_ft2DeferredLogPending) {
      m_autoCQPeriodsMissed = 0;
    } else if (!m_receivedReplyThisPeriod) {
      m_autoCQPeriodsMissed++;
      if (m_autoCQPeriodsMissed >= MAX_MISSED_PERIODS)
        QTimer::singleShot (0, this, [this] { clearDX (); });
    }
    m_receivedReplyThisPeriod = false;
  }

  // DT Feedback Loop: update TimeSyncPanel display (correction disabled via m_dtFeedbackEnabled=false)
  applyDtFeedback();

  m_startAnother=m_loopall;
  if(m_bNoMoreFiles) {
    MessageBox::information_message(this, tr("No more files to open."));
    m_bNoMoreFiles=false;
  }

  if((m_mode=="FT2" or m_mode=="FT4" or m_mode=="FT8")
     and m_latestDecodeTime>=0 and m_ActiveStationsWidget!=NULL) {
    if(!m_diskData and (m_nDecodes==0)) {
      m_latestDecodeTime = (QDateTime::currentMSecsSinceEpoch()/1000) % 86400;
      m_latestDecodeTime =  int(m_latestDecodeTime/m_TRperiod);
      m_latestDecodeTime =  int(m_latestDecodeTime*m_TRperiod);
    }
    ARRL_Digi_Display();  // Update the ARRL_DIGI display
  }

  if(m_mode!="FT8" or dec_data.params.nzhsym==50 or (m_mode=="FT8" and m_multithreadFT8 and (m_hsymStop==dec_data.params.nzhsym))) m_nDecodes=0; //ft8md

  if(m_mode=="Q65" and (m_specOp==SpecOp::NA_VHF or m_specOp==SpecOp::ARRL_DIGI
                        or m_specOp==SpecOp::WW_DIGI or m_specOp==SpecOp::Q65_PILEUP)
                        and m_ActiveStationsWidget!=NULL) {
    refreshPileupList();
  }
}

void MainWindow::applyDtFeedback()
{
  m_dtLastSampleCount = m_dtSamples.size();

  // #7: FT2 adaptive thresholds — need fewer samples due to shorter period
  int minSamples = m_dtMinSamples;
  if (m_mode == "FT2") minSamples = 2;  // FT2: 2 decodes enough (shorter period)

  if (m_dtFeedbackEnabled && m_dtSamples.size() >= minSamples && !m_diskData) {
    // Use median for robustness against outliers
    QVector<double> sorted = m_dtSamples;
    std::sort(sorted.begin(), sorted.end());
    double medianDt = sorted[sorted.size() / 2];

    // #4: Adaptive EMA — conservative to avoid oscillation with NTP active
    // FT2 uses gentler factors since 3.75s period means rapid updates
    if (m_mode == "FT2") {
      if (m_totalDecodesForDt < 10) {
        m_dtSmoothFactor = 0.3;    // FT2 warm-up: moderate convergence
      } else if (qAbs(m_avgDtValue) < 0.1) {
        m_dtSmoothFactor = 0.1;    // FT2 stable: gentle tracking
      } else {
        m_dtSmoothFactor = 0.2;    // FT2 transitional
      }
    } else {
      if (m_totalDecodesForDt < 20) {
        m_dtSmoothFactor = 0.5;    // warm-up: converge quickly
      } else if (qAbs(m_avgDtValue) < 0.1) {
        m_dtSmoothFactor = 0.15;   // stable: maintain precision
      } else {
        m_dtSmoothFactor = 0.3;    // transitional: balanced
      }
    }

    // EMA smoothing of median DT
    if (m_totalDecodesForDt == 0) {
      m_avgDtValue = medianDt;
    } else {
      m_avgDtValue = m_dtSmoothFactor * medianDt + (1.0 - m_dtSmoothFactor) * m_avgDtValue;
    }
    m_totalDecodesForDt += m_dtSamples.size();

    // Convert averaged DT (seconds) to ms correction — negative DT means we're
    // starting too early, so we need positive correction
    // NOTE: Predictive correction (dtRate extrapolation) was removed because it
    // amplified oscillations when combined with NTP feedback. Simple proportional
    // correction is more stable with 3.75s FT2 periods.
    double correctionStep = -m_avgDtValue * 1000.0 * m_dtSmoothFactor;
    bool const ntpStable =
        m_ntpEnabled
        && m_ntpClient
        && m_ntpClient->isSynced()
        && qAbs(m_ntpOffset_ms) < 100.0;
    if (m_mode == "FT2" && ntpStable) {
      // If NTP is healthy, DT feedback must stay conservative.
      correctionStep *= 0.45;
    }

    // Clamp correction step — tighter for FT2 (short period, small steps safer)
    double maxStep = (m_mode == "FT2") ? (ntpStable ? 15.0 : 30.0) : 50.0;
    correctionStep = qBound(-maxStep, correctionStep, maxStep);
    m_dtCorrection_ms += correctionStep;

    // Clamp total correction — tighter for FT2 (should never be far off sync)
    double maxTotal = (m_mode == "FT2") ? (ntpStable ? 180.0 : 300.0) : 500.0;
    m_dtCorrection_ms = qBound(-maxTotal, m_dtCorrection_ms, maxTotal);

    // DT correction is computed for TimeSyncPanel display only — NOT applied
    // to Detector (shifting period boundary degrades decoder performance)

    // #5: NTP vs DT cross-validation — warn if corrections are diverging
    if (m_ntpEnabled && qAbs(m_ntpOffset_ms) > 1.0) {
      bool diverging = qAbs(m_dtCorrection_ms) > 3.0 * qAbs(m_ntpOffset_ms)
                        && m_dtCorrection_ms * m_ntpOffset_ms < 0;  // opposite signs
      if (diverging) {
        m_ntpDtDivergenceCount++;
      } else {
        m_ntpDtDivergenceCount = 0;
      }
    } else {
      m_ntpDtDivergenceCount = 0;
    }
  } else if (m_dtFeedbackEnabled && !m_diskData) {
    // No fresh DT samples this cycle: decay historical correction so UI
    // does not stay pinned at clamp limits after transient conditions.
    if (qAbs(m_dtCorrection_ms) < 0.5) {
      m_dtCorrection_ms = 0.0;
    } else {
      // Decay faster when NTP appears healthy.
      double decay = 0.92;
      if (m_ntpEnabled && m_ntpClient && m_ntpClient->isSynced() && qAbs(m_ntpOffset_ms) < 100.0) {
        decay = 0.85;
      }
      m_dtCorrection_ms *= decay;
    }
    // Keep the averaged DT from becoming stale forever.
    m_avgDtValue *= 0.9;
  }

  // Calculate decode latency
  if (m_decodeStartMs > 0) {
    m_lastDecodeLatencyMs = QDateTime::currentMSecsSinceEpoch() - m_decodeStartMs;
    m_decodeStartMs = 0;
  }

  // Forward timing stats to TimeSyncPanel
  if (m_timeSyncPanel) {
    m_timeSyncPanel->updateDecodeTiming(
      m_dtSamples,
      m_avgDtValue,
      m_dtCorrection_ms,
      m_lastDecodeLatencyMs,
      m_dtLastSampleCount,
      0.0,                      // soundcard drift removed
      m_ntpDtDivergenceCount,
      m_dtSmoothFactor);
  }

  // Show effective DT in the status bar: raw decode DT compensated by NTP offset
  // when NTP is synced. This better reflects net slot timing error.
  double const rawDtMs = m_avgDtValue * 1000.0;
  bool const ntpSyncedForDisplay =
      m_ntpEnabled
      && m_ntpClient
      && m_ntpClient->isSynced();
  double const dtDisplayMs = ntpSyncedForDisplay ? (rawDtMs + m_ntpOffset_ms) : rawDtMs;
  QString text = QString("DT:%1%2ms(%3)")
    .arg(dtDisplayMs > 0 ? "+" : "")
    .arg(dtDisplayMs, 0, 'f', 1)
    .arg(m_dtLastSampleCount);
  dt_correction_label.setText(text);
  dt_correction_label.setToolTip(
      QString("Effective DT: %1%2 ms\nRaw decode DT: %3%4 ms\nNTP offset: %5%6 ms\nInternal correction: %7%8 ms")
          .arg(dtDisplayMs > 0 ? "+" : "")
          .arg(dtDisplayMs, 0, 'f', 1)
          .arg(rawDtMs > 0 ? "+" : "")
          .arg(rawDtMs, 0, 'f', 1)
          .arg(m_ntpOffset_ms > 0 ? "+" : "")
          .arg(m_ntpOffset_ms, 0, 'f', 1)
          .arg(m_dtCorrection_ms > 0 ? "+" : "")
          .arg(m_dtCorrection_ms, 0, 'f', 1));

  double const absDisplayDtMs = qAbs(dtDisplayMs);
  if (m_dtLastSampleCount <= 0) {
    dt_correction_label.setStyleSheet("QLabel{color:#888;background:#333}");
  } else if (absDisplayDtMs < 80.0) {
    dt_correction_label.setStyleSheet("QLabel{color:#000;background:#00ff00}");
  } else if (absDisplayDtMs < 180.0) {
    dt_correction_label.setStyleSheet("QLabel{color:#000;background:#ffff00}");
  } else {
    dt_correction_label.setStyleSheet("QLabel{color:#fff;background:#ff0000}");
  }

  m_dtSamples.clear();
}

void MainWindow::refreshPileupList()
{
  // Update the ActiveStations display for Q65 pileup situation...
      int nlist=0;
      char list[2000];
      char line[36];
      list[0]=0;
      auto fname {QDir::toNativeSeparators(m_config.writeable_data_dir().absoluteFilePath("tsil.3q"))};
      get_q3list_(const_cast<char *> (fname.toLatin1().constData()), &m_diskData, &nlist,
                  &list[0], (FCL)fname.length(), (FCL)2000);
      QString t="";
      QString t0="";
      for(int i=0; i<nlist; i++) {
        memcpy(line,&list[36*i],36);
        t0=QString::fromLatin1(line)+"\n";
        m_callers[i]=t0;
        t+=t0;
      }
      m_ActiveStationsWidget->setClickOK(false);
      m_ActiveStationsWidget->displayRecentStations("Q65-pileup",t);
      m_ActiveStationsWidget->setClickOK(true);
}

void MainWindow::read_log()
{
  static QFile f {QDir {QStandardPaths::writableLocation (QStandardPaths::AppLocalDataLocation)}.absoluteFilePath ("decodium.log")};
  if (f.open (QIODevice::ReadOnly)) {
    QTextStream in(&f);
    QString line,callsign;
    for(int i=0; i<99999; i++) {
      line=in.readLine();
      if(line.length()<=0) break;
      callsign=line.mid(40,6);
      int n=callsign.indexOf(",");
      if(n>0) callsign=callsign.left(n);
      m_EMEworked[callsign]=true;
      m_score++;
    }
    f.close();
  }
  if(m_ActiveStationsWidget!=NULL) {
    m_ActiveStationsWidget->setScore(m_score);
    if(m_mode=="Q65") m_ActiveStationsWidget->setRate(m_score);
  }
}

void MainWindow::ARRL_Digi_Update(DecodedText dt)
{
  if(m_mode=="Q65") {
    m_fetched=0;
    readWidebandDecodes();
    return;
  }

  // Extract information relevant for the ARRL Digi contest
  QString deCall;
  QString deGrid;
  dt.deCallAndGrid(/*out*/deCall,deGrid);
  ActiveCall ac;
  RecentCall rc;

  if(deGrid.contains(grid_regexp)) {
     if(!m_activeCall.contains(deCall) or deGrid!=m_activeCall.value(deCall).grid4) {
       // Transmitting station's call is not already in QMap "m_activeCall", or grid has changed.
       // Insert the call, grid, and associated fixed data into the list.

       QString my_Grid = m_config.my_grid();
       if (my_Grid.length() < 5) my_Grid = m_config.my_grid().left(4)+"mm";
       QString de_Grid= deGrid.left(4)+"mm";
       GeoDistanceInfo const geo = geo_distance (my_Grid, de_Grid, 0.0);
       int points=geo.km/500;
       if(geo.km > 500*points) points += 1;
       points += 1;
       ac.grid4=deGrid;
       ac.bands=".......";
       ac.az=geo.az;
       ac.points=points;
       m_activeCall[deCall]=ac;
     }
  }

  m_points=-1;
  if(m_activeCall.contains(deCall)) {

// Don't display stations we already worked on this band.
    QString band=m_config.bands()->find(m_freqNominal);
    if(band=="160m" and m_activeCall[deCall].bands.indexOf("a")>=0) {m_recentCall.remove(deCall); return;}
    if(band=="80m"  and m_activeCall[deCall].bands.indexOf("b")>=0) {m_recentCall.remove(deCall); return;}
    if(band=="40m"  and m_activeCall[deCall].bands.indexOf("c")>=0) {m_recentCall.remove(deCall); return;}
    if(band=="20m"  and m_activeCall[deCall].bands.indexOf("d")>=0) {m_recentCall.remove(deCall); return;}
    if(band=="15m"  and m_activeCall[deCall].bands.indexOf("e")>=0) {m_recentCall.remove(deCall); return;}
    if(band=="10m"  and m_activeCall[deCall].bands.indexOf("f")>=0) {m_recentCall.remove(deCall); return;}
    if(band=="6m"   and m_activeCall[deCall].bands.indexOf("g")>=0) {m_recentCall.remove(deCall); return;}

    // Update the variable data for this deCall
    rc.dialFreq=m_freqNominal;
    rc.audioFreq=dt.frequencyOffset();
    rc.snr=dt.snr();
    m_latestDecodeTime=dt.timeInSeconds();
    rc.txEven = (m_latestDecodeTime % int(2*m_TRperiod)) > 0;
    rc.ready2call=false;
    bool bCQ=dt.messageWords()[0].left(3)=="CQ ";
    if(bCQ or deGrid=="RR73" or deGrid=="73") rc.ready2call=true;
    rc.decodeTime=m_latestDecodeTime;
    m_recentCall[deCall]=rc;
    m_points=m_activeCall.value(deCall).points;
  }
  updateRate();
}

void MainWindow::ARRL_Digi_Display()
{
  if(m_mode=="Q65") {
    m_fetched=0;
    readWidebandDecodes();
    return;
  }
  if (m_mode == "Fox Mode") { // ARRL_Digi_Display can be shown for other modes
    if (m_ActiveStationsWidget != NULL) {
      m_ActiveStationsWidget->setClickOK(true);
    }
    return;
  }
  QMutableMapIterator<QString,RecentCall> icall(m_recentCall);
  QString deCall,deGrid;
  int age=0;
  int i=0;
  int maxAge=m_ActiveStationsWidget->maxAge();
  int points=0;
  int maxPoints=0;
  int indx[1000];
  float pts[1000];
  QStringList list;

  while (icall.hasNext()) {
    icall.next();
    deCall=icall.key();
    age=int((m_latestDecodeTime - icall.value().decodeTime)/m_TRperiod + 0.5);
    if(age<0) age=age + int(86400/m_TRperiod);
    int itx=1;
    if(icall.value().txEven) itx=0;
    int snr=icall.value().snr;
    int freq=icall.value().audioFreq;
    if(age>maxAge) {
      icall.remove();
    } else {
      bool bReady=false;
      if(age==0 and m_recentCall.value(deCall).ready2call) bReady=true;

      QString bands=m_activeCall[deCall].bands;
      bool bWorkedOnBand=false;
      if(m_currentBand=="160m" and bands.mid(0,1)!=".") bWorkedOnBand=true;
      if(m_currentBand=="80m"  and bands.mid(1,1)!=".") bWorkedOnBand=true;
      if(m_currentBand=="40m"  and bands.mid(2,1)!=".") bWorkedOnBand=true;
      if(m_currentBand=="20m"  and bands.mid(3,1)!=".") bWorkedOnBand=true;
      if(m_currentBand=="15m"  and bands.mid(4,1)!=".") bWorkedOnBand=true;
      if(m_currentBand=="10m"  and bands.mid(5,1)!=".") bWorkedOnBand=true;
      if(m_currentBand=="6m"   and bands.mid(6,1)!=".") bWorkedOnBand=true;

      if((bReady or !m_ActiveStationsWidget->readyOnly()) and !bWorkedOnBand) {
        i++;
        int az=m_activeCall[deCall].az;
        deGrid=m_activeCall[deCall].grid4;
        points=m_activeCall[deCall].points;
        if(points>maxPoints) maxPoints=points;
        float x=float(age)/(maxAge+1);
        if(x>1.0) x=0;
        pts[i-1]=points - x;
        QString t1;
        if(!bReady) t1 = t1.asprintf("  %3d  %+2.2d  %4d  %1d %2d %4d",az,snr,freq,itx,age,points);
        if(bReady)  t1 = t1.asprintf("  %3d  %+2.2d  %4d  %1d %2d*%4d",az,snr,freq,itx,age,points);
//        t1 = (deCall + "   ").left(6) + "  " + m_activeCall[deCall].grid4 + t1 + "  " + bands;
        t1 = (deCall + "   ").left(6) + "  " + m_activeCall[deCall].grid4 + t1;
        list.append(t1);
      }
    }
  }
  if(i==0) return;
  int jz=i;
  m_ActiveStationsWidget->setClickOK(false);
  int maxRecent=qMin(i,m_ActiveStationsWidget->maxRecent());
  decodium::legacy::index_sort_ascending (pts, jz, indx);
  QString t;
  i=0;
  for(int j=jz-1; j>=0; j--) {
    int k=indx[j]-1;
    m_ready2call[i]=list[k];
    i++;
    QString t1=QString::number(i) + ".  ";
    if(i<10) t1=" " + t1;
    t += (t1 + list[k] + "\n");
    if(i>=maxRecent) break;
  }
  bool is_fox_mode = ((m_mode=="FT8" or m_mode=="FT2") && m_specOp == SpecOp::FOX);
  if(m_ActiveStationsWidget!=NULL && !is_fox_mode) m_ActiveStationsWidget->displayRecentStations(m_mode,t);
  m_ActiveStationsWidget->setClickOK(true);
}

void MainWindow::queueActiveWindowHound2(QString line) {
  // Active Window shows what's going on outside of current F/H display rules (calling below 1000Hz e.g.)
  // TODO should we allow calling a station that's calling another station, not us?
  if ((m_mode == "FT8" or m_mode == "FT2") and m_specOp == SpecOp::FOX) {
    // process the line to get the callsign
    QStringList w = line.split(' ', SkipEmptyParts);
    // make sure our call is the first in the list, or the station is CQing (not a directed CQ)
    if  ( (w.size() > 7) &&
          (w[5] == m_config.my_callsign() || w[5] == "<"+m_config.my_callsign()+">" || w[5]=="CQ") &&
          ( w[7].contains(grid_regexp) || w[7].contains(non_r_db_regexp) )){
      QString caller = w[6];
      QString grid = "";
      QString db = w[1];
      int db_i = w[1].toInt();
      db = (db_i >=0 ? "+":"") + QStringLiteral("%1").arg(db_i, (db_i >=0 ? 2:3), 10, QLatin1Char('0')); // +00, -01 etc.
      // houndcall rpt grid
      if (w[7].contains(grid_regexp)) grid = w[7];
      if (w[7].contains(non_r_db_regexp)) {
        LOG_INFO(QString("ActiveStations Window click: %1 called with signal report %2").arg(caller).arg(w[7]));
      }
      if (caller.length() > 2) {
        // make sure it's not already in the queue
        for ( QString hs : m_houndQueue) {
          if (hs.startsWith(caller)) {
            //LOG_INFO(QString("ActiveStations Window click: %1 already in queue. Skipping").arg(hs));
            return;
          }
        }
        // make sure caller is not in fox queue either
        if(m_foxQSOinProgress.contains(caller)) {
          //LOG_INFO(QString("ActiveStations Window click: %1 already in progress. Skipping").arg(caller));
          return;
        }

        QString caller_rpt = (caller+"            ").mid(0,12)+db;
        if (m_houndQueue.count() < MAX_HOUNDS_IN_QUEUE) {
          // add it to the queue
          m_houndQueue.enqueue(caller_rpt + " " + grid);
          refreshHoundQueueDisplay();
          // TODO: remove from active stations window too?
        }
        removeHoundFromCallingList(caller);
      }
    } else {
      LOG_INFO(QString("ActiveStations Window click: skipping %1").arg(line));
    }
  }
}

void MainWindow::callSandP2(int n)
{
  m_specOp=m_config.special_op_id();
  bool bCtrl = (n<0);
  n=qAbs(n)-1;
  if(m_mode!="Q65" and m_ready2call[n]=="") return;
  QStringList w=m_ready2call[n].split(' ', SkipEmptyParts);
  if(m_mode=="Q65" and m_specOp==SpecOp::Q65_PILEUP and n < 40) {
    // This code is for 6m EME DXpedition operator
    w=m_callers[n].split(' ', SkipEmptyParts);
    if (w.size() < 4) return;
    m_deCall=w[2];
    if(bCtrl) {
      // Remove this call from q3list.
      rm_q3list_(const_cast<char *> (m_deCall.toLatin1().constData()), m_deCall.size());
      refreshPileupList();
      return;
    }
    m_deGrid=w[3];
    m_bDoubleClicked=true;               //### needed?
    m_txFirst=true;
    ui->dxCallEntry->setText(m_deCall);
    ui->dxGridEntry->setText(m_deGrid);
    ui->txFirstCheckBox->setChecked(m_txFirst);
    genStdMsgs("-22");
    setTxMsg(3);
    if (!ui->autoButton->isChecked()) ui->autoButton->click(); // Enable Tx
    if(m_transmitting) m_restart=true;
    return;
  }

  if(m_mode=="Q65") {
    if (w.size() < 7) return;
    if(!bCtrl) {                          //Do not reset m_freqNominal if CTRL was down
      double kHz=w[1].toDouble();
      int nMHz=m_freqNominal/1000000;
      m_freqNominal=(nMHz*1000 + kHz)* 1000;
    }
    m_deCall=w[4];
    m_deGrid=w[5];
    m_txFirst=(w[6]=="0");
//    ui->TxFreqSpinBox->setValue(1500);
  } else {
    if (w.size() < 6) return;
    m_deCall=w[0];
    m_deGrid=w[1];
    ui->RxFreqSpinBox->setValue(w[4].toInt());
    m_txFirst = (w[5]=="0");
  }

  if(w[3].left(2)=="30") {
    ui->sbTR->setValue(30);
  } else {
    ui->sbTR->setValue(60);
  }
  if(w[3].right(1)=="A") ui->sbSubmode->setValue(0);
  if(w[3].right(1)=="B") ui->sbSubmode->setValue(1);
  if(w[3].right(1)=="C") ui->sbSubmode->setValue(2);
  if(w[3].right(1)=="D") ui->sbSubmode->setValue(3);
  if(w[3].right(1)=="E") ui->sbSubmode->setValue(4);
  if(w[3].right(1)=="F") ui->sbSubmode->setValue(5);

  m_bDoubleClicked=true;               //### needed?
  ui->dxCallEntry->setText(m_deCall);
  ui->dxGridEntry->setText(m_deGrid);
  if(m_mode=="Q65") {
    ui->rptSpinBox->setValue(w[2].toInt());
    genStdMsgs(w[2]);
  } else {
    genStdMsgs(w[3]);
  }
  setTxMsg(1);
  ui->txFirstCheckBox->setChecked(m_txFirst);
  static qint64 ms0=0;
  qint64 ms=QDateTime::currentMSecsSinceEpoch();
  if(SpecOp::NONE==m_specOp) {
    if(ui->autoButton->isChecked()) {
      if((ms-ms0)>500) ui->autoButton->click(); // Disable Tx on single click
    } else if((ms-ms0)<=500) {
      ui->autoButton->click(); // Enable Tx again, on double click
    }
    if(m_mode=="Q65" && m_ActiveStationsWidget!=NULL) {
      setRig (m_freqNominal);
      setXIT (ui->TxFreqSpinBox->value ());
    }
  } else {
    if(ui->autoButton->isChecked()) {
      if((ms-ms0)<=500) ui->autoButton->click(); // Disable Tx on double click
    } else if((ms-ms0)>500) {
      ui->autoButton->click(); // Enable Tx on single click
    }
  }
  ms0=ms;
  if(m_transmitting) m_restart=true;
}

void MainWindow::activeWorked(QString call, QString band)
{
  QString bands=m_activeCall[call].bands;
  QByteArray ba=bands.toLatin1();
  if(band=="160m") ba[0]='a';
  if(band=="80m")  ba[1]='b';
  if(band=="40m")  ba[2]='c';
  if(band=="20m")  ba[3]='d';
  if(band=="15m")  ba[4]='e';
  if(band=="10m")  ba[5]='f';
  if(band=="6m")   ba[6]='g';
  m_activeCall[call].bands=QString::fromLatin1(ba);
}

