  narg[6] = request.t0_ms;
  narg[7] = request.t1_ms;
  narg[8] = request.maxlines;
  narg[9] = 102;
  narg[10] = request.rxfreq;
  narg[11] = request.ftol;
  narg[12] = 0;
  narg[13] = -1;
  narg[14] = request.aggressive;

