// Takes a decoded CQ line and sets it up for reply
void MainWindow::replyToCQ (QTime time, qint32 snr, float delta_time, quint32 delta_frequency
                            , QString const& mode, QString const& message_text
                            , bool useReply, quint8 modifiers)        //avt 1/1/21
{
  debugToFile(QString{"replyToCq"});    //avt
  if (is_externalCtrlMode()) m_enableButtonNotify = false; //avt 1/29/24

  QString format_string {"%1 %2 %3 %4 %5 %6"};
  auto const& time_string = time.toString ("~" == mode || "&" == mode || "+" == mode
                                           || (m_TRperiod < 60. && ("`" == mode || ":" == mode))
                                           ? "hhmmss" : "hhmm");
  auto text = message_text;
  auto ap_pos = text.lastIndexOf (QRegularExpression {R"((?:\?\s)?(?:a[0-9]|q[0-9][0-9]?)$)"});
  if (ap_pos >= 0)
    {
      // beware of decodes ending on shorter version of wanted call so
      // add a space
      text = text.left (ap_pos).trimmed () + ' ';
    }
  auto message_line = format_string
    .arg (time_string)
    .arg (snr, 3)
    .arg (delta_time, 4, 'f', 1)
    .arg (delta_frequency, 4)
    .arg (mode, -2)
    .arg (text);
  
  QTextCursor cursor;         //avt 12/21/20 set to null
  if (!is_externalCtrlMode())         //avt 12/21/20
  {
    QTextCursor start {ui->decodedTextBrowser->document ()};
    start.movePosition (QTextCursor::End);
    cursor = ui->decodedTextBrowser->document ()->find (message_line, start, QTextDocument::FindBackward);
    if (cursor.isNull ())
    {
      // try again with with -0.0 delta time
      cursor = ui->decodedTextBrowser->document ()->find (format_string
                                                          .arg (time_string)
                                                          .arg (snr, 3)
                                                          .arg ('-' + QString::number (delta_time, 'f', 1), 4)
                                                          .arg (delta_frequency, 4)
                                                          .arg (mode, -2)
                                                          .arg (text), start, QTextDocument::FindBackward);
    }
  }                         //avt 12/21/20

  if (!cursor.isNull () || is_externalCtrlMode()) //avt 11/28/20
    {
      if (!is_externalCtrlMode()) {      //avt 11/20/20 external controller doesn't need user attention
        if (m_config.udpWindowToFront ())
        {
          show ();
          raise ();
          activateWindow ();
        }
        if (m_config.udpWindowRestore () && isMinimized ())
        {
          showNormal ();
          raise ();
        }
      if ((text.contains (QRegularExpression {R"(^(CQ |CQDX |QRZ ))"}))
          || text.contains("73 ") || (ui->cbHoldTxFreq->isChecked ())) {
        // a message we are willing to accept and auto reply to
        m_bDoubleClicked = true;
      }
      }
      else    //avt
      {
        m_bDoubleClicked = true;  //avt 11/15/20 external controller simulating dbl-click
        if (useReply) ui->tx1->setEnabled(true);    //avt 1/1/21 disable skip grid msg, use reply msg instead
      }
     

      DecodedText message {message_line};
      Qt::KeyboardModifiers kbmod {modifiers << 24};
      processMessage (message, kbmod);
      tx_watchdog (false);

      if (!is_externalCtrlMode()) {    //avt
        QApplication::alert (this);   //avt 11/20/20 external controller doesn't want this
      }
      else {    //avt
        debugToFile(QString{"replyToCq    statusUpdate"});    //avt
        statusUpdate();           //avt 11/19/20 external controller needs txFirst info
      }
    }
  else
    {
      qDebug () << "process reply message ignored, decode not found:" << message_line;
    }
  m_enableButtonNotify = true; //avt 1/29/24
}

void MainWindow::locationChange (QString const& location)
{
  QString grid {location.trimmed ()};
  int len;

  // string 6 chars or fewer, interpret as a grid, or use with a 'GRID:' prefix
  if (grid.size () > 6) {
    if (grid.toUpper ().startsWith ("GRID:")) {
      grid = grid.mid (5).trimmed ();
    }
    else {
      // TODO - support any other formats, e.g. latlong? Or have that conversion done external to wsjtx
      return;
    }
  }
  if (MaidenheadLocatorValidator::Acceptable == MaidenheadLocatorValidator ().validate (grid, len)) {
    qDebug() << "locationChange: Grid supplied is " << grid;
    if (m_config.my_grid () != grid) {
      m_config.set_location (grid);
      genStdMsgs (m_rpt, false);
      pskSetLocal ();
      statusUpdate ();
    }
    if (m_worldMapWidget)
      {
        m_worldMapWidget->setHomeGrid(grid);
      }
  } else {
    qDebug() << "locationChange: Invalid grid " << grid;
  }
}

void MainWindow::updateWorldMapFromDecode(DecodedText const& decoded_text)
{
  if (!m_worldMapWidget)
    {
      return;
    }

  auto normalizeCall = [] (QString call)
    {
      call = call.trimmed().toUpper();
      call.remove('<');
      call.remove('>');
      if (call.endsWith(';'))
        {
          call.chop(1);
        }
      return call.trimmed();
    };

  auto callKey = [&normalizeCall] (QString const& call)
    {
      auto normalized = normalizeCall(call);
      if (normalized.isEmpty())
        {
          return QString {};
        }
      auto key = normalizeCall(Radio::base_callsign(normalized));
      if (key.isEmpty())
        {
          key = normalized;
        }
      return key;
    };

  auto myGrid = m_config.my_grid().trimmed().toUpper();
  if (!myGrid.contains(grid_regexp))
    {
      return;
    }

  auto myCall = normalizeCall(m_config.my_callsign());
  auto myBaseCall = normalizeCall(Radio::base_callsign(m_config.my_callsign()));
  auto const myCallKey = callKey(myCall);
  auto const myBaseCallKey = callKey(myBaseCall);

  auto isMine = [&callKey, &myCallKey, &myBaseCallKey] (QString const& call)
    {
      auto key = callKey(call);
      return !key.isEmpty() && (key == myCallKey || key == myBaseCallKey);
    };

  auto rememberGrid = [&] (QString const& call, QString const& grid)
    {
      auto key = callKey(call);
      auto locator = grid.trimmed().toUpper();
      if (key.isEmpty() || !locator.contains(grid_regexp))
        {
          return;
        }
      m_worldMapGridByCall.insert(key, locator.left(6));
    };

  auto loadCall3GridCache = [&] ()
    {
      if (m_worldMapCall3Loaded)
        {
          return;
        }
      m_worldMapCall3Loaded = true;

      QFile fPrimary {m_config.writeable_data_dir().absoluteFilePath("CALL3.TXT")};
      QFile fFallback {QDir::current().absoluteFilePath("CALL3.TXT")};
      QFile * f = &fPrimary;
      if (!f->open(QIODevice::ReadOnly | QIODevice::Text))
        {
          f = &fFallback;
          if (!f->open(QIODevice::ReadOnly | QIODevice::Text))
            {
              return;
            }
        }

      QTextStream in(f);
      while (!in.atEnd())
        {
          auto line = in.readLine().trimmed();
          if (line.isEmpty() || line.startsWith('#') || line.startsWith(';'))
            {
              continue;
            }

          int comma1 = line.indexOf(',');
          if (comma1 <= 0)
            {
              continue;
            }
          int comma2 = line.indexOf(',', comma1 + 1);
          if (comma2 < 0)
            {
              comma2 = line.size();
            }

          auto call = normalizeCall(line.left(comma1));
          auto locator = line.mid(comma1 + 1, comma2 - comma1 - 1).trimmed().toUpper();
          if (call.isEmpty() || !locator.contains(grid_regexp))
            {
              continue;
            }

          auto key = callKey(call);
          if (!key.isEmpty() && !m_worldMapGridByCall.contains(key))
            {
              m_worldMapGridByCall.insert(key, locator.left(6));
            }
        }
    };

  auto lookupGrid = [&] (QString const& call)
    {
      auto key = callKey(call);
      if (key.isEmpty())
        {
          return QString {};
        }
      auto locator = m_worldMapGridByCall.value(key);
      if (locator.isEmpty())
        {
          loadCall3GridCache();
          locator = m_worldMapGridByCall.value(key);
        }
      return locator;
    };

  auto words = decoded_text.messageWords();
  QString word1 = words.size() > 2 ? normalizeCall(words.at(2)) : QString {};
  QString word2 = words.size() > 3 ? normalizeCall(words.at(3)) : QString {};
  QString word3 = words.size() > 4 ? words.at(4).trimmed().toUpper() : QString {};
  bool hasGrid = word3.contains(grid_regexp);
  bool isCqLike = (word1 == "CQ" || word1 == "QRZ" || word1 == "DE");

  // In directed messages like "CALL_TO CALL_FROM GRID", the locator belongs to CALL_FROM (word2).
  // In "CQ CALL GRID", the locator belongs to CALL.
  if (hasGrid)
    {
      if (isCqLike && !word2.isEmpty())
        {
          rememberGrid(word2, word3);
        }
      else if (!word2.isEmpty())
        {
          rememberGrid(word2, word3);
        }
    }

  QString deCall;
  QString deGrid;
  decoded_text.deCallAndGrid(/*out*/deCall, deGrid);
  deCall = normalizeCall(deCall);
  deGrid = deGrid.trimmed().toUpper();
  if (!deCall.isEmpty() && deGrid.contains(grid_regexp) && !isMine(deCall))
    {
      rememberGrid(deCall, deGrid);
    }

  QString remoteCall;
  QString remoteGrid;
  auto role = WorldMapWidget::PathRole::Generic;

  // Standard directed semantics:
  //   CALL_TO CALL_FROM ...  => CALL_FROM (word2) is TX station, CALL_TO (word1) is RX station.
  bool outgoingFromMe = !isCqLike && !word1.isEmpty() && !word2.isEmpty() && isMine(word2) && !isMine(word1);
  bool incomingToMe = !isCqLike && !word1.isEmpty() && !word2.isEmpty() && isMine(word1) && !isMine(word2);

  // Downgrade end-of-QSO messages (73, RR73) to BandOnly to clear the connection line.
  bool isEndOfQso = words.contains("73") || words.contains("RR73");

  bool txMessageActive = decoded_text.isTX() && m_transmitting;
  if (outgoingFromMe || txMessageActive)
    {
      remoteCall = outgoingFromMe ? word1 : QString {};
      if (remoteCall.isEmpty() && !word1.isEmpty() && word1 != "CQ" && word1 != "QRZ" && word1 != "DE" && !isMine(word1))
        {
          remoteCall = word1;
        }
      if (remoteCall.isEmpty() && !word2.isEmpty() && !isMine(word2))
        {
          remoteCall = word2;
        }
      if (remoteCall.isEmpty())
        {
          remoteCall = normalizeCall(ui->dxCallEntry->text());
        }

      if (!remoteCall.isEmpty())
        {
          remoteGrid = lookupGrid(remoteCall);
          auto dxCall = normalizeCall(ui->dxCallEntry->text());
          auto dxGrid = ui->dxGridEntry->text().trimmed().toUpper();
          if (remoteGrid.isEmpty() && callKey(remoteCall) == callKey(dxCall) && dxGrid.contains(grid_regexp))
            {
              remoteGrid = dxGrid.left(6);
              rememberGrid(remoteCall, remoteGrid);
            }
        }

      role = WorldMapWidget::PathRole::OutgoingFromMe;
      if (remoteGrid.contains(grid_regexp))
        {
          m_worldMapWidget->addContact(remoteCall, myGrid, remoteGrid, role);
          return;
        }
    }
  else if (incomingToMe)
    {
      remoteCall = word2;
      remoteGrid = hasGrid ? word3 : lookupGrid(remoteCall);
      role = WorldMapWidget::PathRole::IncomingToMe;
      if (remoteGrid.contains(grid_regexp))
        {
          m_worldMapWidget->addContact(remoteCall, remoteGrid, myGrid, role);
          return;
        }
      if (!remoteCall.isEmpty())
        {
          auto const lookedUp = m_logBook.countries()->lookup(remoteCall);
          if (std::isfinite(lookedUp.latitude) && std::isfinite(lookedUp.longtitude))
            {
              // AD1CCty uses positive west longitudes; convert to standard east-positive.
              QPointF approxLonLat {-static_cast<double>(lookedUp.longtitude),
                                    static_cast<double>(lookedUp.latitude)};
              m_worldMapWidget->addContactByLonLat(remoteCall, approxLonLat, myGrid, role);
              return;
            }
        }
    }
  else
    {
      if (!deCall.isEmpty() && deGrid.contains(grid_regexp) && !isMine(deCall))
        {
          remoteCall = deCall;
          remoteGrid = deGrid;
        }
      else if (isCqLike && !word2.isEmpty() && hasGrid)
        {
          remoteCall = word2;
          remoteGrid = word3;
        }
      role = WorldMapWidget::PathRole::BandOnly;
    }

  if (isEndOfQso)
    {
      if (m_worldMapWidget && !remoteCall.isEmpty())
        {
          m_worldMapWidget->downgradeContactToBand(remoteCall);
        }
      role = WorldMapWidget::PathRole::BandOnly;
    }

  if (!remoteGrid.contains(grid_regexp))
    {
      return;
    }
  if (remoteCall.isEmpty())
    {
      remoteCall = deCall;
    }
  if (role == WorldMapWidget::PathRole::BandOnly)
    {
      m_worldMapWidget->addContact(remoteCall, remoteGrid, remoteGrid, role);
    }
  else
    {
      m_worldMapWidget->addContact(remoteCall, remoteGrid, myGrid, role);
    }
}

void MainWindow::replayDecodes ()
{
  // we accept this request even if the setting to accept UDP requests
  // is not checked

  // attempt to parse the decoded text
  for (QTextBlock block = ui->decodedTextBrowser->document ()->firstBlock (); block.isValid (); block = block.next ())
    {
      auto message = block.text ();
      message = message.left (message.indexOf (QChar::Nbsp)); // discard
                                                              // any
                                                              // appended info
      if (message.size() >= 4 && message.left (4) != "----")
        {
          auto const& parts = message.split (' ', SkipEmptyParts);
          if (parts.size () >= 5 && parts[3].contains ('.')) {
            postWSPRDecode (false, parts);
          } else {
            postDecode (false, DecodedText {message});      //avt 1/5/24
          }
      }
  }
  statusChanged ();
}

void MainWindow::postDecode (bool is_new, DecodedText decoded_text)      //avt 12/5/20
{
  QString message = decoded_text.string();      //avt 1/5/24
  auto const& decode = message.trimmed ();
  auto const message_text = udp_decode_message_text (decode);
  auto const& parts = decode.left (22).split (' ', SkipEmptyParts);
  if (parts.size () >= 5 && (!is_externalCtrlMode() || decoded_text.isStandardMessage()))    //avt
    {
      //QApplication::beep();    //avt
      auto has_seconds = parts[0].size () > 4;
      m_messageClient->decode (is_new
                               , QTime::fromString (parts[0], has_seconds ? "hhmmss" : "hhmm")
                               , parts[1].toInt ()
                               , parts[2].toFloat (), parts[3].toUInt (), parts[4]
                               , message_text
                               , QChar {'?'} == decode.mid (has_seconds ? 24 + 36 : 22 + 36, 1)
                               , m_diskData);
    }

  if (is_new && m_remoteCommandServer)
    {
      m_remoteCommandServer->publishBandActivityLine(decode);
    }

  if (!is_new) return;    //avt 8/22/23

  if (m_worldMapWidget)
    {
      m_worldMapWidget->setHomeGrid(m_config.my_grid());
      updateWorldMapFromDecode(decoded_text);
    }

  //avt 1/2/21
  bool callB4;
  bool callB4onBand;
  bool countryB4;
  bool countryB4onBand;
  bool gridB4;
  bool gridB4onBand;
  bool continentB4;
  bool continentB4onBand;
  bool CQZoneB4;
  bool CQZoneB4onBand;
  bool ITUZoneB4;
  bool ITUZoneB4onBand;
 
  //avt 1/2/21
  QString grid;
  QString call;
  decoded_text.deCallAndGrid(call, grid);

  if(call.length()<3) return;
  if(!call.contains(QRegularExpression("[0-9]|[A-Z]"))) return;

  //avt 10/26/21
  if (((QDateTime::currentMSecsSinceEpoch() / 1000 - m_secBandChanged) > 4*int(m_TRperiod)/4)) {  //avt 7/7/22 band wasn't recently changed
    debugToFile(QString {"enqueueDecod deCall:%1 m_mode:%2 grid:%3 m_currentBand:%4"}.arg(call).arg(m_mode).arg(grid).arg(m_currentBand));
    auto const& looked_up = m_logBook.countries ()->lookup (call);
    m_logBook.match (call, m_mode, grid, looked_up, callB4, countryB4, gridB4, continentB4, CQZoneB4, ITUZoneB4);
    debugToFile(QString {"             callB4:%1 countryB4:%2 continentB4:%3"}.arg(callB4).arg(countryB4).arg(continentB4));
    m_logBook.match (call, m_mode, grid, looked_up, callB4onBand, countryB4onBand, gridB4onBand,
                 continentB4onBand, CQZoneB4onBand, ITUZoneB4onBand, m_currentBand);
    debugToFile(QString {"             callB4onBand:%1 countryB4onBand:%2 continentB4onBand:%3"}.arg(callB4onBand).arg(countryB4onBand).arg(continentB4onBand));

    int nAz = -1;
    int nDkm = -1;
    if (grid.contains(grid_regexp)) {
      GeoDistanceInfo const geo = geo_distance (m_config.my_grid (), grid, 0.0);
      nAz = geo.az;
      nDkm = geo.km;
    }

    //DX defined as not same continent
    bool isDx = looked_up.continent != m_logBook.countries()->lookup(m_config.my_callsign()).continent; //avt 10/14/21
    debugToFile(QString {"             isDx:%1 entity_name:%2"}.arg(isDx).arg(looked_up.entity_name));
    enqueueDecode (decoded_text, false, true, isDx, !callB4onBand, !callB4, !countryB4onBand, !countryB4, looked_up.entity_name, AD1CCty::continent(looked_up.continent), nAz, nDkm);   //avt 5/4/24
  }
  else
  {
    debugToFile("postDecode   band is invalid " + call);
  }
}

void MainWindow::enqueueDecode (DecodedText decoded_text, bool modifier, bool autoGen, bool isDx, bool isNewCallOnBand, bool isNewCall, bool isNewCountryOnBand, bool isNewCountry, QString country, QString continent, int az, int dist)      //avt 5/4/24
{
  QString message = decoded_text.string();      //avt 1/1/21
  auto const& decode = message.trimmed ();
  auto const message_text = udp_decode_message_text (decode);
  auto const& parts = decode.left (22).split (' ', SkipEmptyParts);
  if (parts.size () >= 5 && (!is_externalCtrlMode() || decoded_text.isStandardMessage()))   //avt 1/1/21
    {
      auto has_seconds = parts[0].size () > 4;
      m_messageClient->enqueue_decode (autoGen        //avt 1/3/21
                               , QTime::fromString (parts[0], has_seconds ? "hhmmss" : "hhmm")
                               , parts[1].toInt ()
                               , parts[2].toFloat (), parts[3].toUInt (), parts[4]
                               , message_text
                               , isDx                 //avt 1/3/21
                               , modifier
                               , isNewCallOnBand
                               , isNewCall            //avt 5/6/24
                               , isNewCountryOnBand
                               , isNewCountry
                               , country              //avt 5/4/24
                               , continent            //avt 5/6/24
                               , az
                               , dist);
    }
}

void MainWindow::postWSPRDecode (bool is_new, QStringList parts)
{
  if (parts.size () < 8)
    {
      parts.insert (6, "");
    }
  m_messageClient->WSPR_decode (is_new, QTime::fromString (parts[0], "hhmm"), parts[1].toInt ()
                                , parts[2].toFloat (), Radio::frequency (parts[3].toFloat (), 6)
                                , parts[4].toInt (), parts[5], parts[6], parts[7].toInt ()
                                , m_diskData);
}

void MainWindow::networkError (QString const& e)
{
  if (m_splash && m_splash->isVisible ()) m_splash->hide ();
  if (MessageBox::Retry == MessageBox::warning_message (this, tr ("Network Error")
                                                        , tr ("Error: %1\nUDP server %2:%3")
                                                        .arg (e)
                                                        .arg (m_config.udp_server_name ())
                                                        .arg (m_config.udp_server_port ())
                                                        , QString {}
                                                        , MessageBox::Cancel | MessageBox::Retry
                                                        , MessageBox::Cancel))
    {
      // retry server lookup
      m_messageClient->set_server (m_config.udp_server_name (), m_config.udp_interface_names ());
    }
}

