void MainWindow::on_autoCQButton_clicked(bool checked)
{
    m_autoCQ = checked;
  clearPendingAutoLogSnapshot ();
  clearAutoCqPartnerLock ();
  m_ft2DeferredLogPending = false;
  m_logAfterOwn73 = false;
  m_ft2QuickPeerSignaled = false;
  m_nTx73 = 0;
    if (checked) {
      m_txRetryCount = 0;
      m_lastNtx = -1;
      m_cqRetryCount = 0;
      // Start Auto CQ: select TX6 (CQ message), enable auto-sequence and auto TX
      m_ntx = 6;
      ui->txrb6->setChecked(true);
      m_QSOProgress = CALLING;
      m_bCallingCQ = true;
      m_bAutoReply = false;
      ui->cbAutoSeq->setChecked(true);
      genStdMsgs(QString{});    // regenerate CQ message
      if (!m_auto) {
        ui->autoButton->setChecked(true);
        on_autoButton_clicked(true);
      }
      if (kEnableAutoCqCallerQueue && SpecOp::FOX != m_specOp) {
        // Mostra caller queue nel tab dedicato
        ui->tabWidget->setCurrentIndex(1);
        refreshCallerQueueDisplay();
      }
    } else {
      m_txRetryCount = 0;
      m_lastNtx = -1;
      m_cqRetryCount = 0;
      m_bCallingCQ = false;
      m_callerQueue.clear();
      if (kEnableAutoCqCallerQueue) {
        // Torna al tab principale
        ui->tabWidget->setCurrentIndex(0);
        ui->houndQueueTextBrowser->erase();
      }
    }
    check_button_color();
}

