void MainWindow::bandHoppingTimer()
{
    if(ui->pbBandHopping->isChecked()) {
    static int startIndex = 0;
    int nextStartIndex = startIndex +1;
    switch (startIndex){
    case 0:
            startIndex = nextStartIndex;  // band hopping every other minute
            return;
    case 1:
            m_displayBand = false;
            bandHopping();
            startIndex = 0;
            return;
     }
   }
}

//if external controller is connected, does the current mode use the external controller commansd?
bool MainWindow::is_externalCtrlMode() const    //avt 6/7/22
{
  return m_externalCtrl && (QString {CONTROLLER_MODES_SUPPORTED}).contains(m_mode) && m_specOp == SpecOp::NONE;    //avt 3/26/24
}

void MainWindow::initExternalCtrl()    //avt 12/5/20
{ 
  bool active = is_externalCtrlMode();
  //debugToFile(QString{"initExternal m_externalCtrl:%1 is_externalCtrlMode:%2"}.arg(m_externalCtrl).arg(active));
  m_config.setExternalCtrlMode(active);   //avt  10/2/25 order inportant, do first

  if (active)
  {
    ui->cbAutoSeq->setChecked(true);
    ui->cbAutoSeq->setEnabled(false); //avt 11/22/20
    ui->txFirstCheckBox->setEnabled(!m_listenMode);   //avt 2/1/24
    ui->genStdMsgsPushButton->setEnabled(!m_listenMode);   //avt 2/2/24
    ui->respondComboBox->setVisible(false); //avt
    ui->respondComboBox->setCurrentIndex(0); //avt
    ui->pbBestSP->setEnabled(false);  //avt 2/28/21
  } else {
    if (ui->cbAutoSeq->isVisible()) ui->cbAutoSeq->setEnabled(true); //avt 11/22/20
    if (ui->txFirstCheckBox->isVisible()) ui->txFirstCheckBox->setEnabled(true);  //avt 2/1/24
    if (ui->genStdMsgsPushButton->isVisible()) ui->genStdMsgsPushButton->setEnabled(true);   //avt 2/2/24
    ui->respondComboBox->setVisible(m_mode!="JT65" and m_mode!="JT9");  //avt
    ui->pbBestSP->setEnabled(m_mode=="FT2" or m_mode=="FT4");  //avt 2/28/21
    m_dblClk = false; //avt 1/1/21
    m_checkCmd = "";  //avt 1/1/21
    m_dxCall = "";    //avt 11/12/21
    m_bOffset = false;//avt 11/13/21
    m_txHaltClk = false;  //avt 12/18/21
    m_txEnableClk = false;  //avt 1/28/24
    m_enableButtonNotify = true;  //avt 1/23/24
    m_listenMode = false; //avt 2/1/24
    ui->label->setStyleSheet ("QLabel{color: #000000}");
  }
  check_button_color();     //avt 10/1/25
}

//External Controller did not send heartbeat msg in time
void MainWindow::externalCtrlDisconnected()     //avt 12/16/21
{
  m_externalCtrl = false;
  initExternalCtrl();
  on_stopTxButton_clicked();
  debugToFile("extCtrlDisc  Heartbeat not rec'd");
  QTimer::singleShot (500, this, SLOT (showExternalCtrlDisconnect()));
}

void MainWindow::showExternalCtrlDisconnect()     //avt 12/16/21
{
  QApplication::beep();
  showStatusMessage("Controller disconnected");
  QApplication::alert (this);
}


void MainWindow::debugToFile(QString str)       //avt 11/25/19
{
  if (!m_debugLog) return;

  QString file = m_config.writeable_data_dir().absoluteFilePath("debug.txt");
  QFile outputFile(file);
  if (!outputFile.open(QIODevice::ReadWrite | QIODevice::Append))
  {
     MessageBox::warning_message (this, tr ("Unable to open log file"), file);
     return;
  }
 
  QTextStream outStream(&outputFile);
  if (!str.isEmpty()) {
    outStream << QDateTime::currentDateTimeUtc().toString("HH:mm:ss.zzz ").toLocal8Bit() << str;
  }
  outStream << Qt::endl;
  outputFile.close();
}

bool MainWindow::legacyWidgetLogicallyVisible (QWidget const * widget) const
{
  return widget && (widget->isVisible () || (m_embeddedShellMode && !widget->isHidden ()));
}

bool MainWindow::legacyAutoSeqEnabled () const
{
  return ui
      && ui->cbAutoSeq
      && ui->cbAutoSeq->isChecked ()
      && (((legacyWidgetLogicallyVisible (ui->cbAutoSeq)) && ui->cbAutoSeq->isEnabled ())
          || is_externalCtrlMode ());
}

bool MainWindow::legacyRespondSelectionEnabled () const
{
  return ui
      && ui->respondComboBox
      && legacyWidgetLogicallyVisible (ui->respondComboBox);
}

void MainWindow::debugAutoCq(QString const& event, QString const& details)
{
  if (!m_debugLog || !ui) return;

  auto const currentBase = Radio::base_callsign (ui->dxCallEntry->text ()).trimmed ().toUpper ();
  auto const hisBase = Radio::base_callsign (m_hisCall).trimmed ().toUpper ();
  auto const lockedBase = Radio::base_callsign (m_autoCqLockedCall).trimmed ().toUpper ();
  QString line = QString {
      "autoCQ      event:%1 partner:%2 his:%3 lock:%4 ntx:%5 qso:%6 calling:%7 autoReply:%8 txRetry:%9 lastNtx:%10 cqRetry:%11 missed:%12 queue:%13"
    }
      .arg (event,
            currentBase.isEmpty () ? QString {"-"} : currentBase,
            hisBase.isEmpty () ? QString {"-"} : hisBase,
            lockedBase.isEmpty () ? QString {"-"} : lockedBase)
      .arg (m_ntx)
      .arg (qsoProgressDebugName (m_QSOProgress))
      .arg (m_bCallingCQ ? 1 : 0)
      .arg (m_bAutoReply ? 1 : 0)
      .arg (m_txRetryCount)
      .arg (m_lastNtx)
      .arg (m_cqRetryCount)
      .arg (m_autoCQPeriodsMissed)
      .arg (m_callerQueue.size ());
  if (!details.isEmpty ()) {
    line += " " + details;
  }
  debugToFile (line);
}

