void MainWindow::onRemoteSetTxEnabledRequested(QString const& commandId, bool enabled)
{
  Q_UNUSED(commandId);
  if (!ui || !ui->autoButton)
    {
      return;
    }
  if (!enabled)
    {
      if (ui->autoCQButton && ui->autoCQButton->isChecked())
        {
          ui->autoCQButton->setChecked(false);
          on_autoCQButton_clicked(false);
        }
      if (ui->autoButton->isChecked())
        {
          ui->autoButton->setChecked(false);
          on_autoButton_clicked(false);
        }
      if (m_transmitting || m_tune)
        {
          on_stopTxButton_clicked();
        }
    }
  else if (ui->autoButton->isChecked() != enabled)
    {
      ui->autoButton->setChecked(enabled);
      on_autoButton_clicked(enabled);
    }
  showStatusMessage(enabled ? tr("Remote TX enabled") : tr("Remote TX disabled"));
}

void MainWindow::onRemoteSetAutoCqRequested(QString const& commandId, bool enabled)
{
  Q_UNUSED(commandId);
  if (!ui || !ui->autoCQButton)
    {
      return;
    }

  if (ui->autoCQButton->isChecked() != enabled)
    {
      ui->autoCQButton->setChecked(enabled);
      on_autoCQButton_clicked(enabled);
    }

  showStatusMessage(enabled ? tr("Remote Auto CQ enabled") : tr("Remote Auto CQ disabled"));
}

void MainWindow::setAutoSpotEnabled(bool enabled, bool fromRemote)
{
  bool const changed = (m_autoSpotEnabled != enabled);
  if (!changed && m_autoSpotCheckBox && m_autoSpotCheckBox->isChecked() == enabled)
    {
      return;
    }
  m_autoSpotEnabled = enabled;
  if (m_autoSpotCheckBox && m_autoSpotCheckBox->isChecked() != enabled)
    {
      bool const blocked = m_autoSpotCheckBox->blockSignals(true);
      m_autoSpotCheckBox->setChecked(enabled);
      m_autoSpotCheckBox->blockSignals(blocked);
    }
  if (m_settings)
    {
      m_settings->setValue(QStringLiteral("AutoSpotEnabled"), enabled);
    }
  if (!changed)
    {
      return;
    }
  showStatusMessage(fromRemote
                    ? (enabled ? tr("Remote AutoSpot enabled") : tr("Remote AutoSpot disabled"))
                    : (enabled ? tr("AutoSpot enabled") : tr("AutoSpot disabled")));
}

void MainWindow::onRemoteSetAutoSpotRequested(QString const& commandId, bool enabled)
{
  Q_UNUSED(commandId);
  setAutoSpotEnabled(enabled, true);
}

void MainWindow::onRemoteSetMonitoringRequested(QString const& commandId, bool enabled)
{
  Q_UNUSED(commandId);
  if (!ui || !ui->monitorButton)
    {
      return;
    }
  if (enabled && m_transmitting)
    {
      showStatusMessage(tr("Remote Monitoring ignored: cannot enable while transmitting"));
      return;
    }

  bool const checkboxMismatch = (ui->monitorButton->isChecked() != enabled);
  bool const stateMismatch = (m_monitoring != enabled);
  if (checkboxMismatch)
    {
      ui->monitorButton->setChecked(enabled);
    }
  if (checkboxMismatch || stateMismatch)
    {
      on_monitorButton_clicked(enabled);
    }
  showStatusMessage(enabled ? tr("Remote Monitoring enabled") : tr("Remote Monitoring disabled"));
}

void MainWindow::onRemoteSetAsyncL2Requested(QString const& commandId, bool enabled)
{
  Q_UNUSED(commandId);
  if (!ui || !ui->cbAsyncDecode)
    {
      return;
    }
  if (m_mode != "FT2")
    {
      showStatusMessage(tr("Remote Async L2 ignored: not in FT2 mode"));
      return;
    }
  if (!enabled)
    {
      bool const oldBlocked = ui->cbAsyncDecode->blockSignals (true);
      ui->cbAsyncDecode->setChecked (true);
      ui->cbAsyncDecode->blockSignals (oldBlocked);
      showStatusMessage(tr("Remote Async L2 ignored: mandatory in FT2 mode"));
      return;
    }
  ui->cbAsyncDecode->setChecked(true);
  showStatusMessage(tr("Remote Async L2 enabled (mandatory in FT2)"));
}

